export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    You are a world-class RCM Facilitator (SAE JA1011 Specialist).
    Analyze the following operational context: ${contextText}

    TASK:
    Generate a highly granular and exhaustive FMECA (Failure Mode, Effects, and Criticality Analysis) in a classical RCM structure.

    HIERARCHY RULES:
    1. Identify a small set (usually 3-7) of major asset Functions (Primary and Secondary).
    2. For each Function, identify the standard Functional Failures.
    3. Group components and failure modes strictly under these consolidated functions.

    QUALITY RULES:
    1. EXHAUSTIVE DUAL-PASS ANALYSIS: 
       - PASS 1 (Technical): Identify every possible intrinsic/hardware failure (wear, fatigue, corrosion, erosion, material degradation).
       - PASS 2 (Human Factors): Identify failures caused by human intervention (Maintenance-induced) or misuse (Operational-induced).
    2. HUMAN FACTOR EXAMPLES:
       - MAINTENANCE-INDUCED: (e.g., 'Bearing seizure due to over-lubrication', 'Motor burnout due to misalignment during replacement', 'Seal leak due to improper tool usage/wrong torque').
       - OPERATIONAL-INDUCED: (e.g., 'Pump cavitation due to incorrect valve positioning/suction starvation', 'Thermal fatigue due to rapid cycling outside of SOP').
    3. TASK ASSIGNMENT:
       - For human error/procedural causes, you MUST suggest 'Training' or 'Procedural Change' as the maintenance task.
       - For design-related causes, suggest 'Redesign'.
       - For wear-related causes, suggest 'Condition Monitoring' or 'Time-Based' tasks.
    4. QUANTITY: This must be a HIGH-FIDELITY full-asset analysis. Generate between 30 and 40 unique failure modes mapped to the consolidated function list.
    5. ISO 14224: Ensure the iso14224Code accurately reflects the failure class.
  `;

  const contents: any[] = [{ parts: [{ text: prompt }] }];
  if (fileData) {
    contents[0].parts.push({
      inlineData: {
        mimeType: fileData.mimeType,
        data: fileData.data
      }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents[0].parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: rcmSchema,
      temperature: 0.7
    }
  });

  const rawItems = JSON.parse(response.text || "[]");
  return rawItems.map((item: any) => ({
    ...item,
    id: `rcm-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
    rpn: (item.severity || 1) * (item.occurrence || 1) * (item.detection || 1),
    isNew: true
  }));
};

