export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    Analyze this asset as a WHOLE assembly, not component-by-component.
    Operational Context: ${contextText}

    HIERARCHICAL ANALYSIS PROCESS:
    1. Identify all Primary Functions (the reasons the asset exists) and Secondary Functions (safety, protection, economy, appearance).
    2. Define Functional Failures for each function (how the asset fails to perform those functions).
    3. Identify which specific components logically contribute to those failures.
    4. List failure modes for those components, mapping them back up to the functional failure.

    STRICT FORMATTING:
    - Populate 'functionType' with exactly 'Primary' or 'Secondary'.
    - Consolidate functions. Do not create a new function for every component. Group logically.
    - Generate exhaustive technical and human-induced failure modes (30-40 records).
  `;

  const contents: any[] = [{ parts: [{ text: prompt }] }];
  if (fileData) {
    contents[0].parts.push({
      inlineData: { mimeType: fileData.mimeType, data: fileData.data }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents[0].parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: rcmSchema,
      temperature: 0.7
    }
  });

  const rawItems = JSON.parse(response.text || "[]");
  return rawItems.map((item: any) => ({
    ...item,
    id: `rcm-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
    rpn: (item.severity || 1) * (item.occurrence || 1) * (item.detection || 1),
    isNew: true
  }));
};

export const generateInspectionSheet = async (item: RCMItem): Promise<InspectionSheet> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `Generate inspection protocol for: ${item.component}, Failure Mode: ${item.failureMode}, Task: ${item.maintenanceTask}`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: inspectionSchema,
    }
  });
  return JSON.parse(response.text || "{}") as InspectionSheet;
};

export const generateComponentIntel = async (componentName: string): Promise<ComponentIntel> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `Physical identification guide for: ${componentName}`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: componentIntelSchema,
    }
  });
  return JSON.parse(response.text || "{}") as ComponentIntel;
};

export const extractOperationalContext = async (fileData: FileData): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = "Extract and summarize the operational context focus on environment, duty cycles, and specifications.";
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: prompt },
        { inlineData: { mimeType: fileData.mimeType, data: fileData.data } }
      ]
    }
  });
  return response.text || "";
};

