      <button onClick={() => setIsOpen(!isOpen)} className={`relative w-16 h-16 rounded-[1.8rem] flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 z-[60] border-2 border-white ${isOpen ? 'bg-slate-900 rotate-90' : 'bg-indigo-600'}`}>
