  const handleExcelTechnicalExtract = () => {
    setIsExtracting(true);
    const headers = [
      "Function", 
      "Functional failure", 
      "Component", 
      "Failure mode", 
      "Proposed Task", 
      "Frequency",
      "Step", 
      "Action",
      "Responsibility",
      "Duration",
      "Acceptance Criteria"
    ];

    const rows: string[] = [];

    processedData.forEach(item => {
      const steps = item.inspectionSheet?.steps || [];
      const baseInfo = [
        item.function,
        item.functionalFailure,
        item.component,
        item.failureMode,
        item.maintenanceTask,
        item.interval
      ];

      const responsibility = item.inspectionSheet?.responsibility || "";
      const duration = item.inspectionSheet?.estimatedTime || "";

      if (steps.length > 0) {
        steps.forEach((step, idx) => {
          const rowData = idx === 0 
            ? [...baseInfo, step.step, step.description, responsibility, duration, step.criteria]
            : ["", "", "", "", "", "", step.step, step.description, "", "", step.criteria];

          rows.push(rowData.map(v => `"${String(v || '').replace(/"/g, '""')}"`).join(","));
        });
      } else {
        const rowData = [...baseInfo, "", "", "", "", ""];
        rows.push(rowData.map(v => `"${String(v || '').replace(/"/g, '""')}"`).join(","));
      }
    });

    // sep=, is a special instruction for Excel to use commas as the delimiter
    // \uFEFF is the UTF-8 Byte Order Mark (BOM) which helps Excel identify the encoding
    const csvContent = "\uFEFFsep=,\n" + [headers.join(","), ...rows].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);
    link.setAttribute('download', `RCM_Technical_Extract_${new Date().toISOString().slice(0, 10)}.csv`);
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setTimeout(() => setIsExtracting(false), 1500);
  };

