            <tbody className="divide-y divide-slate-100 text-sm bg-white">
              {processedData.length === 0 ? (
                <tr><td colSpan={14} className="text-center py-20 bg-slate-50/30"><div className="flex flex-col items-center gap-2 text-slate-400"><FilterX size={48} strokeWidth={1} /><p className="font-medium">No matches found for active filters.</p><button onClick={clearAllFilters} className="text-indigo-600 text-xs hover:underline mt-2">Clear all filters</button></div></td></tr>
              ) : (
                processedData.map((item, idx) => {
                  if (!item) return null;
                  const isEditing = editingId === item.id; const isRegenerating = regeneratingIds.has(item.id);

                  // Hierarchy checks for grouping: FunctionType > FunctionName > FF > Component
                  const prevItem = idx > 0 ? processedData[idx - 1] : null;
                  const showFunctionType = !prevItem || prevItem.functionType !== item.functionType;
                  const showFunction = showFunctionType || prevItem.function !== item.function;
                  const showFunctionalFailure = showFunction || prevItem.functionalFailure !== item.functionalFailure;
                  const showComponent = showFunctionalFailure || prevItem.component !== item.component;

                  if (isEditing && editForm) {
                    return (
                      <tr key={item.id} className="bg-indigo-50/30 ring-2 ring-indigo-500/20 z-10 relative">
                        <td className="px-6 py-4 align-top"><select value={editForm.functionType} onChange={(e) => handleChange('functionType', e.target.value)} className="w-full px-2 py-1 border rounded text-[10px] font-black uppercase"><option value="Primary">Primary</option><option value="Secondary">Secondary</option></select></td>
                        <td className="px-6 py-4 align-top"><textarea rows={2} value={editForm.function} onChange={(e) => handleChange('function', e.target.value)} className="w-full px-2 py-1 border rounded text-xs" /></td>
                        <td className="px-6 py-4 align-top"><textarea rows={2} value={editForm.functionalFailure} onChange={(e) => handleChange('functionalFailure', e.target.value)} className="w-full px-2 py-1 border rounded text-xs" /></td>
                        <td className="px-6 py-4 align-top"><input type="text" value={editForm.component} onChange={(e) => handleChange('component', e.target.value)} className="w-full px-2 py-1 border rounded" /></td>
                        <td className="px-6 py-4 align-top">
                          <select 
                            value={editForm.consequenceCategory} 
                            onChange={(e) => handleChange('consequenceCategory', e.target.value)}
                            className="w-full px-2 py-1 border rounded text-xs"
