                <th className="px-6 py-4 min-w-[180px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('function')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">Function Name {renderSortIcon('function')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Search..." value={searchFilters.function} onChange={(e) => handleSearchChange('function', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all" /></div></div></th>
