                <th className="px-6 py-4 min-w-[120px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('iso14224Code')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">ISO 14224 {renderSortIcon('iso14224Code')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Search..." value={searchFilters.iso14224Code} onChange={(e) => handleSearchChange('iso14224Code', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none transition-all" /></div></div></th>
                <th className="px-6 py-4 min-w-[200px]"><div className="flex flex-col gap-2"><button onClick={() => requestSort('failureMode')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">Failure Mode {renderSortIcon('failureMode')}</button><div className="relative group/search"><Search size={12} className="absolute left-2 top-1/2 -translate-y-1/2 text-slate-400" /><input type="text" placeholder="Search..." value={searchFilters.failureMode} onChange={(e) => handleSearchChange('failureMode', e.target.value)} className="w-full pl-7 pr-2 py-1 bg-white border border-slate-200 rounded text-[10px] font-normal lowercase focus:ring-1 focus:ring-indigo-500 focus:border-indigo-500 outline-none" /></div></div></th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/50 border-l border-slate-200">S</th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/50">O</th>
                <th className="px-2 py-4 w-12 text-center bg-slate-100/50">D</th>
                <th className="px-4 py-4 min-w-[100px] text-left bg-slate-100/50 border-r border-slate-200"><button onClick={() => requestSort('rpn')} className="flex items-center gap-2 hover:text-indigo-600 transition-colors">RPN {renderSortIcon('rpn')}</button></th>
                <th className="px-6 py-4 min-w-[180px]">Proposed Task</th>
                <th className="px-6 py-4 w-16 text-center">
                  <button onClick={() => requestSort('inspectionSheet')} className="flex items-center gap-1 hover:text-indigo-600 transition-colors mx-auto">
                    Insp. {renderSortIcon('inspectionSheet')}
                  </button>
                </th>
                <th className="px-6 py-4 w-20 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm bg-white">
              {processedData.length === 0 ? (
                <tr><td colSpan={14} className="text-center py-20 bg-slate-50/30"><div className="flex flex-col items-center gap-2 text-slate-400"><FilterX size={48} strokeWidth={1} /><p className="font-medium">No matches found for active filters.</p><button onClick={clearAllFilters} className="text-indigo-600 text-xs hover:underline mt-2">Clear all filters</button></div></td></tr>
              ) : (
                processedData.map((item, idx) => {
                  if (!item) return null;
                  const isEditing = editingId === item.id; const isRegenerating = regeneratingIds.has(item.id);
                  const isGeneratingIntel = generatingIntelIds.has(item.id);

                  // Hierarchy checks for grouping: FunctionType > FunctionName > FF > Component
                  const prevItem = idx > 0 ? processedData[idx - 1] : null;
                  const showFunctionType = !prevItem || prevItem.functionType !== item.functionType;
                  const showFunction = showFunctionType || prevItem.function !== item.function;
                  const showFunctionalFailure = showFunction || prevItem.functionalFailure !== item.functionalFailure;
                  const showComponent = showFunctionalFailure || prevItem.component !== item.component;

                  if (isEditing && editForm) {
                    return (
                      <tr key={item.id} className="bg-indigo-50/30 ring-2 ring-indigo-500/20 z-10 relative">
                        <td className="px-6 py-4 align-top"><select value={editForm.functionType} onChange={(e) => handleChange('functionType', e.target.value)} className="w-full px-2 py-1 border rounded text-[10px] font-black uppercase"><option value="Primary">Primary</option><option value="Secondary">Secondary</option></select></td>
                        <td className="px-6 py-4 align-top"><textarea rows={2} value={editForm.function} onChange={(e) => handleChange('function', e.target.value)} className="w-full px-2 py-1 border rounded text-xs" /></td>
                        <td className="px-6 py-4 align-top"><textarea rows={2} value={editForm.functionalFailure} onChange={(e) => handleChange('functionalFailure', e.target.value)} className="w-full px-2 py-1 border rounded text-xs" /></td>
                        <td className="px-6 py-4 align-top"><input type="text" value={editForm.component} onChange={(e) => handleChange('component', e.target.value)} className="w-full px-2 py-1 border rounded" /></td>
                        <td className="px-6 py-4 align-top">
                          <select 
                            value={editForm.consequenceCategory} 
                            onChange={(e) => handleChange('consequenceCategory', e.target.value)}
                            className="w-full px-2 py-1 border rounded text-xs"
                          >
                            {CONSEQUENCE_LABELS.map(cat => <option key={cat} value={cat}>{cat}</option>)}
                          </select>
                        </td>
                        <td className="px-6 py-4 align-top"><input type="text" value={editForm.iso14224Code} onChange={(e) => handleChange('iso14224Code', e.target.value)} className="w-full px-2 py-1 border rounded text-xs" /></td>
                        <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={2} value={editForm.failureMode} onChange={(e) => handleChange('failureMode', e.target.value)} className="w-full px-2 py-1 border rounded" /><textarea rows={3} value={editForm.failureEffect} onChange={(e) => handleChange('failureEffect', e.target.value)} className="w-full px-2 py-1 border rounded" /></div></td>
                        <td className="px-2 py-4 align-top bg-white/50 border-l"><input type="number" min="1" max="10" value={editForm.severity} onChange={(e) => handleChange('severity', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.occurrence} onChange={(e) => handleChange('occurrence', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-2 py-4 align-top bg-white/50"><input type="number" min="1" max="10" value={editForm.detection} onChange={(e) => handleChange('detection', parseInt(e.target.value))} className="w-full text-center border rounded" /></td>
                        <td className="px-4 py-4 align-top text-center font-bold bg-white/50 border-r">{(editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1)}</td>
                        <td className="px-6 py-4 align-top"><div className="space-y-2"><textarea rows={3} value={editForm.maintenanceTask} onChange={(e) => handleChange('maintenanceTask', e.target.value)} className="w-full border rounded" /><input type="text" value={editForm.interval} onChange={(e) => handleChange('interval', e.target.value)} className="w-full border rounded" /></div></td>
                        <td className="px-6 py-4 align-top text-center text-slate-300"><File size={20} className="mx-auto" /></td>
                        <td className="px-6 py-4 align-top text-right"><div className="flex flex-col gap-2 items-end"><button onClick={handleSave} className="p-2 bg-emerald-500 text-white rounded"><Save size={16} /></button><button onClick={handleCancel} className="p-2 bg-slate-200 text-slate-600 rounded"><X size={16} /></button></div></td>
                      </tr>
                    );
                  }
                  const rpn = item.rpn || 0; const rpnStyle = getRPNColorStyle(rpn);
                  const consCat = item.consequenceCategory || '';
                  const isNew = item.isNew === true;
                  const isPrimary = item.functionType === 'Primary';

                  return (
                    <tr key={item.id} className={`group hover:bg-slate-50 ${isRegenerating || isGeneratingIntel ? 'opacity-60 bg-slate-50' : ''} ${barFilter === item.id ? 'bg-indigo-50/50' : ''} ${isNew ? 'bg-emerald-50/60 transition-colors' : ''}`}>
                      <td className="px-6 py-4 align-top">
                        {showFunctionType ? (
                          <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-1 rounded-md border ${isPrimary ? 'bg-slate-900 text-white border-slate-900 shadow-sm' : 'bg-white text-slate-400 border-slate-200'}`}>
                            {item.functionType}
                          </span>
                        ) : null}
                      </td>
                      <td className={`px-6 py-4 align-top text-[11px] leading-tight ${isPrimary ? 'text-slate-900 font-black uppercase' : 'text-slate-600 font-bold'}`}>
                        {showFunction ? item.function : null}
                      </td>
                      <td className="px-6 py-4 align-top text-[11px] leading-tight text-slate-600 italic">
                        {showFunctionalFailure ? item.functionalFailure : null}
                      </td>
                      <td className="px-6 py-4 font-medium align-top leading-tight text-xs">
                        {showComponent ? (
                          <div className="flex items-center gap-2">
                            <span className="flex-1 text-slate-700">{item.component}</span>
                            <button 
                              onClick={() => handleIntelClick(item)} 
                              disabled={isGeneratingIntel}
                              className={`p-1.5 rounded-full border transition-all flex items-center justify-center shrink-0 ${
                                isGeneratingIntel 
                                  ? 'bg-amber-50 text-amber-500 border-amber-200 cursor-wait' 
                                  : item.componentIntel && item.componentIntel.description
                                    ? 'text-indigo-500 border-indigo-100 hover:bg-indigo-50 opacity-0 group-hover:opacity-100'
                                    : 'bg-amber-100 text-amber-600 border-amber-300 hover:bg-amber-200 hover:scale-110 shadow-sm'
                              }`} 
                              title={item.componentIntel?.description ? "Component Intelligence" : "Synthesize Physical Intel"}
                            >
                              {isGeneratingIntel ? <RefreshCw size={12} className="animate-spin" /> : <Info size={14} />}
                            </button>
                          </div>
                        ) : null}
                      </td>
                      <td className="px-6 py-4 align-top">
                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded-full border ${consCat.includes('Hidden') ? 'bg-orange-50 text-orange-700 border-orange-200' : 'bg-blue-50 text-blue-700 border-blue-200'}`}>
                          {consCat}
                        </span>
                      </td>
                      <td className="px-6 py-4 align-top">
                        <span className="text-[10px] font-mono font-bold text-indigo-600 bg-indigo-50 px-1.5 py-0.5 rounded border border-indigo-100 uppercase">
                          {item.iso14224Code}
                        </span>
                      </td>
                      <td className="px-6 py-4 align-top"><div className="space-y-2"><div className="font-semibold text-[11px] border p-1 rounded inline-block bg-white shadow-sm leading-tight">{item.failureMode}</div><div className="text-slate-500 text-[10px] leading-relaxed line-clamp-2">{item.failureEffect}</div></div></td>
                      <td className="px-2 py-4 align-middle text-center border-l"><span className={getScoreColor(item.severity || 0)}>{item.severity || 0}</span></td>
                      <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.occurrence || 0)}>{item.occurrence || 0}</span></td>
                      <td className="px-2 py-4 align-middle text-center"><span className={getScoreColor(item.detection || 0)}>{item.detection || 0}</span></td>
                      <td className="px-4 py-4 align-middle border-r"><div className="flex flex-col gap-1"><span className={`text-xs font-bold ${rpnStyle.text}`}>{rpn}</span><div className="w-full h-1 bg-slate-100 rounded-full overflow-hidden"><div className={`h-full ${rpnStyle.bar}`} style={{width: `${Math.min((rpn/400)*100, 100)}%`}}></div></div></div></td>
                      <td className="px-6 py-4 align-top group/interval">
                        <div className="font-medium text-xs leading-tight">
                           {item.maintenanceTask}
                           {(item.taskType === 'Training' || item.taskType === 'Procedural Change') && (
                             <span className="ml-2 px-1.5 py-0.5 bg-purple-50 text-purple-600 text-[8px] font-black uppercase rounded border border-purple-100">Human Factor Fix</span>
                           )}
                        </div>
                        <button 
                          onClick={() => setOptimizingItem(item)}
                          className="text-[10px] text-slate-400 font-mono mt-1 hover:text-indigo-600 hover:bg-indigo-50 px-1.5 py-0.5 rounded transition-all flex items-center gap-1 group-hover/interval:border group-hover/interval:border-indigo-100"
                        >
                          <Target size={10} className="opacity-0 group-hover/interval:opacity-100" />
                          {item.interval}
                        </button>
                      </td>
                      <td className="px-6 py-4 align-middle text-center">
                         {isRegenerating ? <RefreshCw size={20} className="animate-spin text-indigo-500 mx-auto" /> : item.inspectionSheet ? <button onClick={() => setViewSheet({ item })} className="text-emerald-500 hover:scale-110 transition-transform"><FileCheck size={22} /></button> : <button onClick={() => handleGenerateSingleSheet(item)} className="text-slate-300 hover:text-indigo-500"><File size={22} /></button>}
                      </td>
                      <td className="px-6 py-4 align-middle text-right opacity-0 group-hover:opacity-100 transition-opacity"><div className="flex justify-end gap-1"><button onClick={() => handleEdit(item)} className="p-1 text-slate-400 hover:text-indigo-600"><Pencil size={16} /></button><button onClick={() => handleDelete(item.id)} className="p-1 text-slate-400 hover:text-red-600"><Trash2 size={16} /></button></div></td>
                    </tr>
                  );
                })
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis, extractOperationalContext } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Folder } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle,
  FileSearch,
  CheckCircle2
} from 'lucide-react';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExtracting, setIsLoadingExtracting] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isFinished, setIsFinished] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  // Initializing to true so it shows every time the app loads
  const [showWelcome, setShowWelcome] = useState(true);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);
  const isFinishedRef = useRef(isFinished);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
    isFinishedRef.current = isFinished;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies, isFinished]);

  // Load studies on initialization
  useEffect(() => {
    const initData = async () => {
      try {
        const [studies, fetchedFolders] = await Promise.all([
          getAllStudies(),
          getAllFolders()
        ]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 30 seconds)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      const hasContent = (resultsRef.current && resultsRef.current.length > 0) || contextTextRef.current.trim().length > 0;
      if (hasContent) {
        handleSaveStudy(true);
      }
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type || 'application/octet-stream',
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleExtractContext = async () => {
    if (!fileData) return;
    setIsLoadingExtracting(true);
    setError(null);
    try {
      const extractedText = await extractOperationalContext(fileData);
      setContextText(extractedText);
      setActiveTab('manual');
      // Scroll to top of manual tab area
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err: any) {
      setError("Document analysis failed. Please ensure the file is not corrupted.");
    } finally {
      setIsLoadingExtracting(false);
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const currentFinished = isFinishedRef.current;
    const studies = savedStudiesRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    // Find the existing study to preserve timestamp during auto-saves so it stays in its list position
    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      fileName: currentFile?.name,
      folderId: existingStudy?.folderId, // Preserve folder association
      isFinished: currentFinished
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }

      // Feedback mechanism: turn button green
      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);

    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleDuplicateStudy = async (study: SavedStudy) => {
    const newId = `study-copy-${Date.now()}`;
    const duplicatedStudy: SavedStudy = {
      ...study,
      id: newId,
      name: `${study.name} (Copy)`,
      timestamp: Date.now(),
      folderId: undefined, // Always shown in uncategorized
      isFinished: false
    };

    try {
      await saveStudyToDB(duplicatedStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      // Automatically load the duplicate
      handleLoadStudy(duplicatedStudy);
    } catch (e) {
      console.error("Duplicate failed", e);
      setError("Failed to duplicate study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setIsFinished(!!study.isFinished);
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setIsFinished(false);
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  // Folder Actions
  const handleNewFolder = async (name: string) => {
    const folder: Folder = {
      id: `folder-${Date.now()}`,
      name,
      timestamp: Date.now()
    };
    try {
      await saveFolderToDB(folder);
      const freshFolders = await getAllFolders();
      setFolders(freshFolders);
    } catch (e) {
      console.error("New folder failed", e);
    }
  };

  const handleRenameFolder = async (id: string, name: string) => {
    const folder = folders.find(f => f.id === id);
    if (!folder) return;
    try {
      await saveFolderToDB({ ...folder, name });
      const freshFolders = await getAllFolders();
      setFolders(freshFolders);
    } catch (e) {
      console.error("Rename folder failed", e);
    }
  };

  const handleDeleteFolder = async (id: string) => {
    try {
      // Delete all studies associated with this folder
      const studiesToDelete = savedStudies.filter(s => s.folderId === id);
      for (const study of studiesToDelete) {
        await deleteStudyFromDB(study.id);
      }

      await deleteFolderFromDB(id);

      const [freshFolders, freshStudies] = await Promise.all([
        getAllFolders(),
        getAllStudies()
      ]);
      setFolders(freshFolders);
      setSavedStudies(freshStudies);

      // Reset view if active study was deleted as part of the folder
      if (currentStudyId && studiesToDelete.some(s => s.id === currentStudyId)) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete folder failed", e);
    }
  };

  const handleMoveStudyToFolder = async (studyId: string, folderId?: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    try {
      await saveStudyToDB({ ...study, folderId });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Move to folder failed", e);
    }
  };

  const handleToggleStudyFinished = async (studyId: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    const nextStatus = !study.isFinished;

    try {
      await saveStudyToDB({ ...study, isFinished: nextStatus });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);

      // If we're currently viewing this study, update current state too
      if (currentStudyId === studyId) {
        setIsFinished(nextStatus);
      }
    } catch (e) {
      console.error("Toggle finished failed", e);
    }
  };

  // Export/Import Logic
  const handleExportStudy = (study: SavedStudy) => {
    const dataStr = JSON.stringify(study, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${study.name.replace(/\s+/g, '_')}_RCM_Analysis.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleExportFolder = (folder: Folder) => {
    const folderStudies = savedStudies.filter(s => s.folderId === folder.id);
    const bundle = {
      type: 'folder_bundle',
      folder: folder,
      studies: folderStudies
    };
    const dataStr = JSON.stringify(bundle, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${folder.name.replace(/\s+/g, '_')}_RCM_Bundle.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportStudy = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const content = e.target?.result as string;
        const importedData = JSON.parse(content);

        if (importedData.type === 'folder_bundle') {
          // Process folder bundle
          const newFolderId = `folder-imported-${Date.now()}`;
          const newFolder: Folder = {
            ...importedData.folder,
            id: newFolderId,
            timestamp: Date.now()
          };

          await saveFolderToDB(newFolder);

          for (const study of importedData.studies) {
            const finalStudy: SavedStudy = {
              ...study,
              id: `study-imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
              timestamp: Date.now(),
              folderId: newFolderId
            };
            await saveStudyToDB(finalStudy);
          }

          const [freshFolders, freshStudies] = await Promise.all([
            getAllFolders(),
            getAllStudies()
          ]);
          setFolders(freshFolders);
          setSavedStudies(freshStudies);

        } else {
          // Process standard study
          const importedStudy = importedData as SavedStudy;
          if (!importedStudy.name || !importedStudy.items) {
            throw new Error("Invalid study format");
          }

          const finalStudy: SavedStudy = {
            ...importedStudy,
            id: `study-imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            timestamp: Date.now(),
            folderId: undefined
          };

          await saveStudyToDB(finalStudy);
          const freshStudies = await getAllStudies();
          setSavedStudies(freshStudies);
          handleLoadStudy(finalStudy);
        }

      } catch (err) {
        console.error("Import failed", err);
        setError("Failed to import. Ensure the file is a valid RCM Pro JSON or Bundle.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder isOpen={showContextBuilder} onClose={() => setShowContextBuilder(false)} onComplete={(builtContext) => setContextText(builtContext)} onUndo={handleUndo} canUndo={history.length > 0} />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies} 
          folders={folders}
          currentStudyId={currentStudyId} 
          onSelect={handleLoadStudy} 
          onDelete={handleDeleteStudy} 
          onDuplicate={handleDuplicateStudy}
          onNew={handleNewStudy} 
          onNewFolder={handleNewFolder}
          onRenameFolder={handleRenameFolder}
          onDeleteFolder={handleDeleteFolder}
          onMoveStudy={handleMoveStudyToFolder}
          onExport={handleExportStudy}
          onExportFolder={handleExportFolder}
          onImport={handleImportStudy}
          onToggleFinished={handleToggleStudyFinished}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                   <input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" />
                   {isFinished && (
                     <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-md animate-in zoom-in-95">
                        <CheckCircle2 size={12} fill="currentColor" className="fill-emerald-600/20" />
                        <span className="text-[9px] font-black uppercase tracking-widest">Finished</span>
                     </div>
                   )}
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5 font-bold animate-pulse"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-3 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white border-emerald-600 shadow-emerald-200 scale-[1.02]' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.</p>
              </div>
            )}
            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Manual Synthesis</button>
                <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge Upload</button>
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Description</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div><div className="relative flex items-center gap-2"><div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md"><Sparkles size={16} className="text-white fill-white animate-pulse" /></div><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder="e.g., Centrifugal Pump P-101 is critical for line availability. It operates in a high-temperature environment..." value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg,.docx" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p><p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, DOCX, TXT and Images</p></>) : (<div className="flex items-center gap-5 w-full max-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p></div><button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20} /></button></div>)}</div>
                     {fileData && (
                       <div className="flex justify-center mt-6">
                         <button 
                           onClick={handleExtractContext} 
                           disabled={isExtracting}
                           className={`flex items-center gap-3 px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl active:scale-95 ${isExtracting ? 'bg-indigo-400 text-white cursor-wait' : 'bg-white text-indigo-600 border border-indigo-100 hover:bg-indigo-50 shadow-indigo-100/50'}`}
                         >
                           {isExtracting ? <Loader2 size={16} className="animate-spin" /> : <FileSearch size={16} />}
                           {isExtracting ? "Synthesizing Document..." : "Extract & Structure Context"}
                         </button>
                       </div>
                     )}
                  </div>
                )}
                {error && (<div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500"><AlertTriangle size={18} />{error}</div>)}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">{results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500" /><span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span></label>)}<button onClick={handleGenerate} disabled={isLoading || isExtracting} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 shadow-indigo-300 hover:shadow-indigo-300 hover:-translate-y-1'} ${(isLoading || isExtracting) ? 'opacity-50' : ''}`}>{isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}{isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate RCM Analysis")}</button></div>
              </div>
            </div>
            {results && <AnalysisResult data={results} studyName={studyName} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { RCMItem, FileData, InspectionSheet, ComponentIntel } from "../types";

// Define the expected output schema for structured JSON
const rcmSchema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      functionType: { 
        type: Type.STRING, 
        enum: ['Primary', 'Secondary'],
        description: "The category of the function."
      },
      function: { 
        type: Type.STRING,
        description: "The asset-level function description. Example: 'Maintain 50 bar discharge pressure' or 'Provide structural containment of lubricant'."
      },
      functionalFailure: { 
        type: Type.STRING,
        description: "The specific way the function is lost (e.g., 'Total loss of discharge pressure', 'External lubricant leakage')."
      },
      component: { 
        type: Type.STRING, 
        description: "The specific component within the assembly that contributes to this functional failure." 
      },
      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { 
            type: Type.STRING, 
            description: "Concise technical physical description. No quotes." 
          },
          location: { type: Type.STRING, description: "Location on asset." },
          visualCues: { type: Type.STRING, description: "Identification markers." }
        },
        required: ["description", "location", "visualCues"]
      },
      failureMode: { 
        type: Type.STRING,
        description: "[Mechanism] due to [Cause]. Include technical and human-induced causes."
      },
      failureEffect: { 
        type: Type.STRING,
        description: "Operational and safety impact."
      },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ]
      },
      iso14224Code: { 
        type: Type.STRING,
        description: "Strict ISO 14224 Failure Mechanism Code. Use only standard 3-letter codes: BRD (Breakdown), LOP (Loss of Power), ELP (External Leakage), INL (Internal Leakage), VIB (Abnormal Vibration), OHE (Overheating), STP (Spurious Stop), FTS (Failure to Start), FTC (Failure to Close), FTO (Failure to Open), UST (Spurious Start), NOI (Abnormal Noise), LCP (Low Output), OTH (Other)."
      },
      criticality: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
      severity: { type: Type.INTEGER },
      occurrence: { type: Type.INTEGER },
      detection: { type: Type.INTEGER },
      maintenanceTask: { 
        type: Type.STRING,
        description: "Exactly one technical maintenance task. STRICT RULE: Do not combine multiple tasks (e.g. avoid 'Inspect and Lubricate'). If multiple actions are required for the same failure mode, create multiple separate items in this array."
      },
      interval: { type: Type.STRING },
      taskType: {
        type: Type.STRING,
        enum: [
          'Condition Monitoring', 
          'Time-Based', 
          'Run-to-Failure', 
          'Redesign',
          'Failure Finding',
          'Lubrication',
          'Servicing',
          'Restoration',
          'Replacement',
          'Training',
          'Procedural Change'
        ]
      }
    },
    required: ["functionType", "component", "componentIntel", "function", "functionalFailure", "failureMode", "failureEffect", "consequenceCategory", "iso14224Code", "criticality", "severity", "occurrence", "detection", "maintenanceTask", "interval", "taskType"]
  }
};

const inspectionSchema = {
  type: Type.OBJECT,
  properties: {
    responsibility: { type: Type.STRING },
    estimatedTime: { type: Type.STRING },
    safetyPrecautions: { type: Type.STRING },
    toolsRequired: { type: Type.STRING },
    steps: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          step: { type: Type.INTEGER },
          description: { type: Type.STRING },
          criteria: { type: Type.STRING },
          technique: { type: Type.STRING }
        },
        required: ["step", "description", "criteria", "technique"]
      }
    }
  },
  required: ["responsibility", "estimatedTime", "safetyPrecautions", "toolsRequired", "steps"]
