import { GoogleGenAI, Type } from "@google/genai";
import { RCMItem, FileData, InspectionSheet, ComponentIntel } from "../types";

// Define the expected output schema for structured JSON
const rcmSchema = {
  type: Type.ARRAY,
  items: {
    type: Type.OBJECT,
    properties: {
      functionType: { 
        type: Type.STRING, 
        enum: ['Primary', 'Secondary'],
        description: "The category of the function."
      },
      function: { 
        type: Type.STRING,
        description: "The asset-level function description. Example: 'Maintain 50 bar discharge pressure' or 'Provide structural containment of lubricant'."
      },
      functionalFailure: { 
        type: Type.STRING,
        description: "The specific way the function is lost (e.g., 'Total loss of discharge pressure', 'External lubricant leakage')."
      },
      component: { 
        type: Type.STRING, 
        description: "The specific component within the assembly that contributes to this functional failure." 
      },
      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { 
            type: Type.STRING, 
            description: "Concise technical physical description. No quotes." 
          },
          location: { type: Type.STRING, description: "Location on asset." },
          visualCues: { type: Type.STRING, description: "Identification markers." }
        },
        required: ["description", "location", "visualCues"]
      },
      failureMode: { 
        type: Type.STRING,
        description: "[Mechanism] due to [Cause]. Include technical and human-induced causes."
      },
      failureEffect: { 
        type: Type.STRING,
        description: "Operational and safety impact."
      },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ]
      },
      iso14224Code: { 
        type: Type.STRING,
        enum: ["BRD", "LOP", "ELP", "INL", "VIB", "OHE", "STP", "FTS", "FTC", "FTO", "UST", "NOI", "LCP", "OTH"],
        description: "Strict ISO 14224 Failure Mechanism Code. Use ONLY the 3-letter shorthand code. NO descriptive text or brackets."
      },
      criticality: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
      severity: { type: Type.INTEGER },
      occurrence: { type: Type.INTEGER },
      detection: { type: Type.INTEGER },
      maintenanceTask: { 
        type: Type.STRING,
        description: "Exactly one technical maintenance task. STRICT RULE: Do not combine multiple tasks (e.g. avoid 'Inspect and Lubricate'). If multiple actions are required for the same failure mode, create multiple separate items in this array."
      },
      interval: { type: Type.STRING },
      taskType: {
        type: Type.STRING,
        enum: [
          'Condition Monitoring', 
          'Time-Based', 
          'Run-to-Failure', 
          'Redesign',
          'Failure Finding',
          'Lubrication',
          'Servicing',
          'Restoration',
          'Replacement',
          'Training',
          'Procedural Change'
        ]
      }
    },
    required: ["functionType", "component", "componentIntel", "function", "functionalFailure", "failureMode", "failureEffect", "consequenceCategory", "iso14224Code", "criticality", "severity", "occurrence", "detection", "maintenanceTask", "interval", "taskType"]
  }
};

const inspectionSchema = {
  type: Type.OBJECT,
  properties: {
    responsibility: { type: Type.STRING },
    estimatedTime: { type: Type.STRING },
    safetyPrecautions: { type: Type.STRING },
    toolsRequired: { type: Type.STRING },
    steps: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          step: { type: Type.INTEGER },
          description: { type: Type.STRING },
          criteria: { type: Type.STRING },
          technique: { type: Type.STRING }
        },
        required: ["step", "description", "criteria", "technique"]
      }
    }
  },
  required: ["responsibility", "estimatedTime", "safetyPrecautions", "toolsRequired", "steps"]
};

const componentIntelSchema = {
  type: Type.OBJECT,
  properties: {
    description: { type: Type.STRING },
    location: { type: Type.STRING },
    visualCues: { type: Type.STRING }
  },
  required: ["description", "location", "visualCues"]
};

export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    Analyze this asset as a WHOLE assembly, not component-by-component.
    Operational Context: ${contextText}

    HIERARCHICAL ANALYSIS PROCESS:
    1. Identify all Primary Functions and Secondary Functions.
    2. Define Functional Failures for each function.
    3. Identify which specific components logically contribute to those failures.
    4. List failure modes for those components.

    ISO 14224 STRICT DATA INTEGRITY:
    - You MUST map every failure mode to its standard ISO 14224 3-letter taxonomy code in 'iso14224Code'.
    - USE ONLY: 'BRD', 'LOP', 'ELP', 'INL', 'VIB', 'OHE', 'STP', 'FTS', 'FTC', 'FTO', 'UST', 'NOI', 'LCP', or 'OTH'.
    - DO NOT include descriptive labels or full words like "Breakdown" or "Vibration" in the code field. 
    - The output field 'iso14224Code' must be exactly 3 characters.

    STRICT FORMATTING & LOGIC:
    - EXHAUSTIVE ANALYSIS: Generate a high quantity of records (60-80 failure modes).
    - STRATEGIC DEPTH: For critical failure modes (Severity > 7), identify if multiple tasks are required.
    - ONE TASK PER RECORD: Ensure each entry has exactly ONE task. If multiple actions are needed, create separate records for the same failure mode.
    - Populate 'functionType' with 'Primary' or 'Secondary'.
    - Consolidate functions. Group components under their relevant system functions.
  `;

  const contents: any[] = [{ parts: [{ text: prompt }] }];
  if (fileData) {
    contents[0].parts.push({
      inlineData: { mimeType: fileData.mimeType, data: fileData.data }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents[0].parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: rcmSchema,
      temperature: 0.7
    }
  });

  const rawItems = JSON.parse(response.text || "[]");
  return rawItems.map((item: any) => ({
    ...item,
    id: `rcm-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
    rpn: (item.severity || 1) * (item.occurrence || 1) * (item.detection || 1),
    isNew: true
  }));
};

