                    <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-in slide-in-from-bottom-4 duration-500`}>
                      <div className={`flex gap-4 sm:gap-6 max-w-[95%] sm:max-w-[90%] ${m.role === 'user' ? 'flex-row-reverse' : 'flex-row'}`}>
                        <div className={`w-10 h-10 sm:w-12 sm:h-12 rounded-[1rem] sm:rounded-[1.2rem] shrink-0 flex items-center justify-center shadow-2xl ${m.role === 'user' ? 'bg-indigo-600 text-white' : 'bg-slate-900 text-white'}`}>
                          {m.role === 'user' ? <User size={20} /> : <Bot size={22} />}
                        </div>
                        <div className="flex flex-col gap-4 min-w-0">
                          <div className={`p-6 sm:p-8 rounded-[1.8rem] sm:rounded-[2.2rem] shadow-sm border ${
                            m.role === 'user' 
                              ? 'bg-indigo-600 text-white border-indigo-500 rounded-tr-none text-base sm:text-lg font-bold' 
                              : 'bg-white text-slate-800 border-slate-100 rounded-tl-none ring-1 ring-slate-50'
                          }`}>
                            {m.role === 'user' ? <p className="leading-relaxed">{m.content}</p> : renderFormattedMessage(m.content)}
                          </div>

                          {m.isDraft && latestDraft && i === messages.length - 1 && (
                            <div className="bg-slate-50/50 rounded-[2.2rem] sm:rounded-[2.5rem] border border-slate-100 p-6 sm:p-8 space-y-6 mt-2 animate-in fade-in zoom-in-95 duration-700">
                               <div className="flex items-center justify-between">
                                 <div className="flex items-center gap-3">
                                   <div className="p-2 bg-indigo-100 text-indigo-600 rounded-lg"><Settings size={18} /></div>
                                   <h5 className="text-[10px] sm:text-xs font-black text-slate-900 uppercase tracking-widest">Technical Draft</h5>
                                 </div>
                                 <button onClick={() => setShowFullReview(true)} className="text-[9px] sm:text-[10px] font-black text-indigo-600 hover:text-indigo-700 flex items-center gap-2 uppercase tracking-widest">
                                   <Maximize2 size={14} /> Full Review
                                 </button>
                               </div>

                               <div className="bg-white p-6 sm:p-8 rounded-[1.5rem] sm:rounded-[1.8rem] border border-slate-200 shadow-inner text-slate-700 text-[13px] sm:text-[14px] leading-relaxed font-medium whitespace-pre-wrap">
                                 {latestDraft}
                               </div>

                               <div className="flex gap-4">
                                  <button onClick={handleApply} className="flex-1 py-4 sm:py-5 bg-slate-900 text-white rounded-2xl text-[10px] sm:text-[12px] font-black uppercase tracking-[0.2em] hover:bg-indigo-600 transition-all flex items-center justify-center gap-3 shadow-2xl active:scale-95">
                                    Confirm
                                  </button>
                                  <button onClick={() => setShowFullReview(true)} className="px-5 sm:px-6 py-4 sm:py-5 bg-white border border-slate-200 text-slate-500 rounded-2xl text-[10px] sm:text-[12px] font-black uppercase tracking-widest hover:bg-slate-50 transition-all">
                                    Edit Large
                                  </button>
                               </div>
                            </div>
                          )}
                        </div>
                      </div>
                    </div>
                  ))}

                  {isLoading && (
                    <div className="flex justify-start">
                      <div className="flex gap-4 sm:gap-6 items-center">
                        <div className="w-10 h-10 sm:w-12 sm:h-12 rounded-[1rem] sm:rounded-[1.2rem] bg-indigo-50 flex items-center justify-center animate-pulse">
                          <Loader2 size={22} className="text-indigo-600 animate-spin" />
                        </div>
                        <div className="px-5 sm:px-6 py-3 sm:py-4 bg-white border border-slate-100 rounded-full shadow-sm flex items-center gap-3">
                           <span className="text-[9px] sm:text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Synthesis in {language}</span>
                           <div className="flex gap-1.5">
                             <div className="w-1.5 h-1.5 bg-indigo-400 rounded-full animate-bounce [animation-delay:-0.3s]"></div>
                             <div className="w-1.5 h-1.5 bg-indigo-500 rounded-full animate-bounce [animation-delay:-0.15s]"></div>
                             <div className="w-1.5 h-1.5 bg-indigo-600 rounded-full animate-bounce"></div>
                           </div>
                        </div>
                      </div>
                    </div>
                  )}
                </div>
              </div>

              {/* Input Station */}
              <div className="p-6 sm:p-10 shrink-0 border-t border-slate-50 bg-white shadow-[0_-20px_40px_rgba(0,0,0,0.02)]">
                <div className="max-w-4xl mx-auto">
                  <div className="flex gap-4 sm:gap-6">
                    <button 
                      onClick={handleResetConversation}
                      className="p-4 sm:p-6 bg-slate-50 text-slate-400 hover:text-indigo-600 hover:bg-slate-100 rounded-[1.5rem] sm:rounded-[2rem] transition-all border-2 border-slate-50 flex items-center justify-center shrink-0"
                    >
                      <RotateCcw size={20} />
                    </button>
                    <div className="flex-1 relative group">
                      <input 
                        type="text" 
                        value={input}
                        onChange={e => setInput(e.target.value)}
                        onKeyDown={e => e.key === 'Enter' && handleSend()}
                        placeholder={`Talk to MIRA in ${language}...`}
                        className="w-full bg-slate-50 border-2 border-slate-50 rounded-[1.5rem] sm:rounded-[2rem] px-6 sm:px-8 py-4 sm:py-6 text-sm sm:text-base font-bold text-slate-800 focus:bg-white focus:border-indigo-600 focus:ring-4 focus:ring-indigo-100 outline-none transition-all placeholder:text-slate-300 shadow-inner pr-24"
                      />
                    </div>
                    <button 
                      onClick={handleSend}
                      disabled={!input.trim() || isLoading}
                      className="px-6 sm:px-10 bg-slate-900 text-white rounded-[1.5rem] sm:rounded-[2rem] hover:bg-indigo-600 active:scale-95 disabled:opacity-20 transition-all shadow-2xl flex items-center justify-center gap-3 group"
                    >
                      <span className="font-black text-xs sm:text-sm uppercase tracking-widest">Analyze</span>
                      <Send size={18} className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />
                    </button>
                  </div>
                </div>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  X, Send, Sparkles, ChevronDown, 
  Plus, CheckCircle2, Search, 
  UserCheck, ShieldAlert, Zap, Loader2, LayoutGrid, 
  ChevronRight, RotateCcw, Target, Info
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
  language: string;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
  isFacilitatorInsight?: boolean;
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model'; isFacilitator?: boolean }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        const isQuestion = cleanLine.endsWith('?');

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className={`flex-1 text-[13px] font-medium leading-relaxed ${isQuestion ? 'text-indigo-700 font-bold italic' : ''}`}>
                {cleanLine.replace(/^[*|-]\s*/, '')}
              </span>
            </div>
          );
        }

        return (
          <p key={idx} className={`leading-relaxed text-[13px] font-medium ${isQuestion && role === 'model' ? 'bg-indigo-50 p-2 rounded-lg border-l-4 border-indigo-600 text-indigo-900 shadow-sm' : ''}`}>
            {cleanLine}
          </p>
        );
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate, language }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [isOpen, messages]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object') {
            proposals.push({
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              type: a.type || 'ADD',
              reason: a.reason || 'Facilitator recommendation.',
              item: a.item || {},
              applied: false
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse MIRA action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleFacilitatorAudit = async () => {
    if (!data || data.length === 0) return;
    setIsLoading(true);
    setIsOpen(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const studySummary = data.map(i => ({
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        rpn: i.rpn
      }));

      const prompt = `
        CURRENT STUDY: ${JSON.stringify(studySummary)}
        TARGET LANGUAGE: ${language}

        TASK:
        Perform a technical Facilitator Audit in ${language}. You are MIRA. 
        Focus on:
        1. Human-Factor risks.
        2. Strategic gaps.
        3. Reliability improvements.

        MANDATORY: Speak and generate reasons/descriptions in ${language}.
        MANDATORY RESPONSE FORMAT:
        - Conversational text in ${language}.
        - If suggesting a record, include <ACTION> JSON with technical descriptions in ${language}.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: `You are MIRA, the Facilitator. You respond in ${language}. You wrap suggestions in <ACTION> JSON tags.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Audit results generated.", proposals, isFacilitatorInsight: true }]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        CURRENT STUDY DATA: ${JSON.stringify((data || []).slice(-15).map(i => ({ comp: i.component, fail: i.failureMode, task: i.maintenanceTask })))}
        USER SUGGESTION: "${userMsg}"
        TARGET LANGUAGE: ${language}

        FACILITATOR INSTRUCTIONS:
        1. Act as MIRA. Respond in ${language}.
        2. If suggesting changes, SYNTHESIZE full technical records in ${language}.
        3. Every addition MUST be a complete JSON object in <ACTION> tags.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: `You are MIRA. You communicate in ${language}.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Analysis complete.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Facilitator offline." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const s = Number(proposal.item.severity) || 5;
      const o = Number(proposal.item.occurrence) || 3;
      const d = Number(proposal.item.detection) || 4;

      const newItem: RCMItem = {
        id: `rcm-mir-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'Synthesized Component',
        functionType: (proposal.item.functionType as any) || 'Secondary',
        function: proposal.item.function || 'Technical function.',
        functionalFailure: proposal.item.functionalFailure || 'Operational loss.',
        failureMode: proposal.item.failureMode || 'Degradation mechanism.',
        failureEffect: proposal.item.failureEffect || 'Impact.',
        consequenceCategory: (proposal.item.consequenceCategory as ConsequenceCategory) || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'UNC',
        criticality: proposal.item.criticality as any || (s >= 8 ? 'High' : s >= 5 ? 'Medium' : 'Low'),
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        maintenanceTask: proposal.item.maintenanceTask || 'Inspection',
        interval: proposal.item.interval || 'Annually',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        componentIntel: {
          description: proposal.item.componentIntel?.description || 'Synchronized via MIRA.',
          location: proposal.item.componentIntel?.location || 'Asset location.',
          visualCues: proposal.item.componentIntel?.visualCues || 'Visual markers.'
        },
        isNew: true
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE') {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : (item.component === proposal.item?.component && item.failureMode === proposal.item?.failureMode);
        if (isMatch) {
          const updated = { ...item, ...proposal.item, isNew: false };
          updated.severity = Number(updated.severity) || item.severity;
          updated.occurrence = Number(updated.occurrence) || item.occurrence;
          updated.detection = Number(updated.detection) || item.detection;
          updated.rpn = updated.severity * updated.occurrence * updated.detection;
          return updated;
        }
        return item;
      });
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[520px] h-[700px] bg-white rounded-[3rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-slate-900 p-6 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-4">
              <div className="p-2 bg-indigo-500/20 rounded-xl border border-indigo-400/30">
                <Sparkles size={18} className="text-indigo-400" />
              </div>
              <div>
                <h3 className="font-black text-xl tracking-tighter uppercase leading-none">MIRA <span className="text-[10px] text-indigo-400 tracking-widest ml-1">Facilitator</span></h3>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em] mt-1">Facilitating in {language}</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-all"><ChevronDown size={28} /></button>
          </div>

          <div className="bg-indigo-50/50 px-6 py-3 border-b border-indigo-100 flex items-center justify-between gap-3 shrink-0">
             <div className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-widest">
               <ShieldAlert size={14} /> Audit ({language})
             </div>
             <button 
               onClick={handleFacilitatorAudit} 
               disabled={!data || data.length === 0 || isLoading}
               className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all disabled:opacity-30"
             >
               <Search size={12} /> Facilitate Audit
             </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50/50 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-8">
                <div className="w-20 h-20 bg-white text-indigo-600 rounded-[2.2rem] flex items-center justify-center shadow-2xl border border-indigo-50"><UserCheck size={36} /></div>
                <div className="space-y-4">
                  <p className="text-xl font-black text-slate-900 tracking-tighter uppercase leading-tight">Ready to facilitate</p>
                  <p className="text-[13px] text-slate-500 font-medium italic">Communicating in {language}. I guide your study towards human RCM excellence.</p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
                <div className={`max-w-[95%] p-5 rounded-[2rem] shadow-lg relative ${
                  m.role === 'user' 
                    ? 'bg-slate-900 text-white rounded-br-none font-bold text-[14px]' 
                    : 'bg-white text-slate-800 border-2 border-slate-100 rounded-bl-none shadow-slate-100/10'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} isFacilitator={m.isFacilitatorInsight} />
                </div>

                {m.proposals && (
                  <div className="mt-6 w-full space-y-4">
                    {m.proposals.map((p) => (
                      <div key={p.id} className={`bg-white border-2 rounded-[2rem] p-6 shadow-xl relative overflow-hidden transition-all ${p.applied ? 'border-emerald-500 bg-emerald-50/30' : 'border-indigo-100 ring-4 ring-indigo-50/50'}`}>
                        <div className="flex justify-between items-start gap-4">
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-3">
                              <span className={`text-[9px] font-black uppercase tracking-[0.2em] px-2 py-0.5 rounded-full ${p.applied ? 'bg-emerald-500 text-white' : 'bg-indigo-600 text-white'}`}>
                                {p.applied ? 'Synced' : `${p.type} Request`}
                              </span>
                            </div>
                            <h5 className="text-sm font-black text-slate-900 uppercase truncate leading-none mb-2">{p.item?.component || 'New Item'}</h5>
                            <p className="text-[11px] font-bold text-slate-600 leading-tight italic">{p.reason}</p>
                          </div>
                          {!p.applied ? (
                             <button onClick={() => applySingleAction(p.id, i)} className="shrink-0 w-12 h-12 bg-indigo-600 text-white rounded-xl shadow-lg hover:bg-indigo-700 active:scale-90 transition-all flex items-center justify-center">
                               <Plus size={24} />
                             </button>
                          ) : (
                             <div className="shrink-0 w-12 h-12 bg-emerald-500 text-white rounded-xl shadow-lg flex items-center justify-center animate-in zoom-in">
                               <CheckCircle2 size={24} />
                             </div>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-100 p-4 rounded-full flex items-center gap-3 shadow-sm">
                  <Loader2 size={16} className="animate-spin text-indigo-600" />
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic">MIRA synthesizing in {language}...</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="flex gap-4">
              <button onClick={() => setMessages([])} className="p-4 bg-slate-50 text-slate-400 hover:text-indigo-600 rounded-[1.5rem] border border-slate-100 transition-all"><RotateCcw size={20} /></button>
              <div className="flex-1 relative">
                <input type="text" value={input} onChange={e => setInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleSend()} placeholder={`Ask MIRA in ${language}...`} className="w-full bg-slate-50 border-2 border-slate-100 rounded-[1.8rem] px-6 py-4 text-[14px] font-bold focus:border-indigo-600 outline-none transition-all placeholder:text-slate-300 shadow-inner" />
              </div>
              <button onClick={handleSend} disabled={!input.trim() || isLoading} className="p-4 bg-indigo-600 text-white rounded-[1.5rem] hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95"><Send size={20} /></button>
            </div>
          </div>
        </div>
      )}

      <button onClick={() => setIsOpen(!isOpen)} className={`relative w-16 h-16 rounded-[1.8rem] flex items-center justify-center text-white shadow-2xl transition-all hover:scale-110 active:scale-95 z-[60] border-2 border-white ${isOpen ? 'bg-slate-900 rotate-90' : 'bg-indigo-600'}`}>
        {isOpen ? <X size={28} /> : <UserCheck size={28} />}
        {!isOpen && messages.length > 0 && <div className="absolute -top-1 -right-1 w-5 h-5 bg-emerald-500 border-2 border-white rounded-full animate-pulse" />}
      </button>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { generateRCMAnalysis, extractOperationalContext } from './services/geminiService';
import { getAllStudies, saveStudyToDB, deleteStudyFromDB, getAllFolders, saveFolderToDB, deleteFolderFromDB } from './services/db';
import { RCMItem, FileData, SavedStudy, Folder } from './types';
import { AnalysisResult } from './components/AnalysisResult';
import { Sidebar } from './components/Sidebar';
import { SODReference } from './components/SODReference';
import { OperationalContextBuilder } from './components/OperationalContextBuilder';
import { AICopilot } from './components/AICopilot';
import { DecisionLogicModal } from './components/DecisionLogicModal';
import { WelcomeModal } from './components/WelcomeModal';
import { 
  Cpu, 
  Upload, 
  Type, 
  Zap, 
  Loader2, 
  FileCheck,
  Trash2,
  Menu,
  Save,
  Check,
  AlertTriangle,
  BookOpen,
  Sparkles,
  GitBranch,
  Undo2,
  PlusCircle,
  FileSearch,
  CheckCircle2,
  Globe
} from 'lucide-react';

const LANGUAGES = [
  { code: 'English', label: 'English', flag: '🇺🇸' },
  { code: 'Spanish', label: 'Español', flag: '🇪🇸' },
  { code: 'French', label: 'Français', flag: '🇫🇷' },
  { code: 'German', label: 'Deutsch', flag: '🇩🇪' },
  { code: 'Polish', label: 'Polski', flag: '🇵🇱' }
];

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'manual' | 'upload'>('manual');
  const [contextText, setContextText] = useState('');
  const [fileData, setFileData] = useState<FileData | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isExtracting, setIsLoadingExtracting] = useState(false);
  const [results, setResults] = useState<RCMItem[] | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isMerging, setIsMerging] = useState(false);
  const [selectedLanguage, setSelectedLanguage] = useState('English');

  // Undo System State
  const [history, setHistory] = useState<RCMItem[][]>([]);

  // Study Management State
  const [savedStudies, setSavedStudies] = useState<SavedStudy[]>([]);
  const [folders, setFolders] = useState<Folder[]>([]);
  const [currentStudyId, setCurrentStudyId] = useState<string | null>(null);
  const [studyName, setStudyName] = useState<string>("Untitled Analysis");
  const [isFinished, setIsFinished] = useState(false);
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [justSaved, setJustSaved] = useState(false);

  // Reference, Builder & Logic Modal State
  const [showSODReference, setShowSODReference] = useState(false);
  const [showContextBuilder, setShowContextBuilder] = useState(false);
  const [showDecisionLogic, setShowDecisionLogic] = useState(false);
  const [showWelcome, setShowWelcome] = useState(true);

  // Auto-save refs to avoid stale closures in interval
  const resultsRef = useRef(results);
  const contextTextRef = useRef(contextText);
  const fileDataRef = useRef(fileData);
  const studyNameRef = useRef(studyName);
  const currentStudyIdRef = useRef(currentStudyId);
  const savedStudiesRef = useRef(savedStudies);
  const isFinishedRef = useRef(isFinished);
  const selectedLanguageRef = useRef(selectedLanguage);

  useEffect(() => {
    resultsRef.current = results;
    contextTextRef.current = contextText;
    fileDataRef.current = fileData;
    studyNameRef.current = studyName;
    currentStudyIdRef.current = currentStudyId;
    savedStudiesRef.current = savedStudies;
    isFinishedRef.current = isFinished;
    selectedLanguageRef.current = selectedLanguage;
  }, [results, contextText, fileData, studyName, currentStudyId, savedStudies, isFinished, selectedLanguage]);

  // Load studies on initialization
  useEffect(() => {
    const initData = async () => {
      try {
        const [studies, fetchedFolders] = await Promise.all([
          getAllStudies(),
          getAllFolders()
        ]);
        setSavedStudies(studies);
        setFolders(fetchedFolders);
      } catch (e) {
        console.error("Failed to initialize data", e);
        setError("Could not load saved studies. Please refresh.");
      }
    };
    initData();
  }, []);

  // Automatic Save Timer (Every 30 seconds)
  useEffect(() => {
    const autoSaveInterval = setInterval(() => {
      const hasContent = (resultsRef.current && resultsRef.current.length > 0) || contextTextRef.current.trim().length > 0;
      if (hasContent) {
        handleSaveStudy(true);
      }
    }, 30000);

    return () => clearInterval(autoSaveInterval);
  }, []);

  const handleCloseWelcome = () => {
    setShowWelcome(false);
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;
    if (file.size > 50 * 1024 * 1024) {
      setError("File size exceeds 50MB limit.");
      return;
    }
    try {
      const reader = new FileReader();
      reader.onloadend = () => {
        const base64String = (reader.result as string).split(',')[1];
        setFileData({
          name: file.name,
          mimeType: file.type || 'application/octet-stream',
          data: base64String
        });
        setError(null);
      };
      reader.readAsDataURL(file);
    } catch (e) {
      setError("Failed to read file.");
    }
  };

  const handleExtractContext = async () => {
    if (!fileData) return;
    setIsLoadingExtracting(true);
    setError(null);
    try {
      const extractedText = await extractOperationalContext(fileData, selectedLanguage);
      setContextText(extractedText);
      setActiveTab('manual');
      window.scrollTo({ top: 0, behavior: 'smooth' });
    } catch (err: any) {
      setError("Document analysis failed. Please ensure the file is not corrupted.");
    } finally {
      setIsLoadingExtracting(false);
    }
  };

  const handleGenerate = async () => {
    if (!contextText && !fileData) {
      setError("Please provide operational context text or upload a file.");
      return;
    }

    setIsLoading(true);
    setError(null);

    if (!isMerging) {
      setResults(null);
      setHistory([]);
    }

    try {
      const data = await generateRCMAnalysis(contextText, fileData, selectedLanguage, isMerging ? (results || []) : []);

      if (isMerging && results) {
        setResults([...results.map(item => ({ ...item, isNew: false })), ...data]);
      } else {
        setResults(data);
      }

    } catch (err: any) {
      setError(err.message || "An error occurred during generation.");
    } finally {
      setIsLoading(false);
    }
  };

  const clearFile = () => {
    setFileData(null);
    const fileInput = document.getElementById('file-upload') as HTMLInputElement;
    if (fileInput) fileInput.value = '';
  };

  // Global Save Function
  const handleSaveStudy = async (isAutoSave: boolean = false) => {
    const currentResults = resultsRef.current;
    const currentContext = contextTextRef.current;
    const currentFile = fileDataRef.current;
    const currentName = studyNameRef.current;
    const currentId = currentStudyIdRef.current;
    const currentFinished = isFinishedRef.current;
    const studies = savedStudiesRef.current;
    const currentLang = selectedLanguageRef.current;

    if (!currentResults && !currentContext && !currentFile) return;

    const nameToSave = currentName.trim() || "Untitled Analysis";
    const idToSave = currentId || `study-${Date.now()}`;

    const existingStudy = studies.find(s => s.id === idToSave);
    const timestampToUse = (isAutoSave && existingStudy) ? existingStudy.timestamp : Date.now();

    const newStudy: SavedStudy = {
      id: idToSave,
      name: nameToSave,
      timestamp: timestampToUse,
      items: (currentResults || []).map(item => ({ ...item, isNew: false })),
      contextText: currentContext,
      language: currentLang,
      fileName: currentFile?.name,
      folderId: existingStudy?.folderId,
      isFinished: currentFinished
    };

    try {
      await saveStudyToDB(newStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (!currentId) {
        setCurrentStudyId(idToSave);
      }

      setJustSaved(true);
      setTimeout(() => setJustSaved(false), 2000);

    } catch (e) {
      console.error("Save failed", e);
      if (!isAutoSave) setError("Failed to save study.");
    }
  };

  const handleDeleteStudy = async (id: string) => {
    try {
      await deleteStudyFromDB(id);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      if (currentStudyId === id) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete failed", e);
      setError("Failed to delete study.");
    }
  };

  const handleDuplicateStudy = async (study: SavedStudy) => {
    const newId = `study-copy-${Date.now()}`;
    const duplicatedStudy: SavedStudy = {
      ...study,
      id: newId,
      name: `${study.name} (Copy)`,
      timestamp: Date.now(),
      folderId: undefined,
      isFinished: false
    };

    try {
      await saveStudyToDB(duplicatedStudy);
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
      handleLoadStudy(duplicatedStudy);
    } catch (e) {
      console.error("Duplicate failed", e);
      setError("Failed to duplicate study.");
    }
  };

  const handleLoadStudy = (study: SavedStudy) => {
    setResults(study.items.map(item => ({ ...item, isNew: false })));
    setHistory([]);
    setContextText(study.contextText);
    setCurrentStudyId(study.id);
    setStudyName(study.name);
    setIsFinished(!!study.isFinished);
    setSelectedLanguage(study.language || 'English');
    setFileData(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleNewStudy = () => {
    setResults(null);
    setHistory([]);
    setContextText('');
    setFileData(null);
    setCurrentStudyId(null);
    setStudyName("Untitled Analysis");
    setIsFinished(false);
    setSelectedLanguage('English');
    setError(null);
    if (window.innerWidth < 768) {
      setIsSidebarOpen(false);
    }
  };

  const handleResultsUpdate = (newData: RCMItem[]) => {
    if (results) {
      setHistory(prev => [...prev.slice(-29), results]);
    }
    setResults(newData);
  };

  const handleUndo = () => {
    if (history.length === 0) return;
    const lastState = history[history.length - 1];
    setHistory(prev => prev.slice(0, -1));
    setResults(lastState);
  };

  // Folder Actions
  const handleNewFolder = async (name: string) => {
    const folder: Folder = {
      id: `folder-${Date.now()}`,
      name,
      timestamp: Date.now()
    };
    try {
      await saveFolderToDB(folder);
      const freshFolders = await getAllFolders();
      setFolders(freshFolders);
    } catch (e) {
      console.error("New folder failed", e);
    }
  };

  const handleRenameFolder = async (id: string, name: string) => {
    const folder = folders.find(f => f.id === id);
    if (!folder) return;
    try {
      await saveFolderToDB({ ...folder, name });
      const freshFolders = await getAllFolders();
      setFolders(freshFolders);
    } catch (e) {
      console.error("Rename folder failed", e);
    }
  };

  const handleDeleteFolder = async (id: string) => {
    try {
      const studiesToDelete = savedStudies.filter(s => s.folderId === id);
      for (const study of studiesToDelete) {
        await deleteStudyFromDB(study.id);
      }

      await deleteFolderFromDB(id);

      const [freshFolders, freshStudies] = await Promise.all([
        getAllFolders(),
        getAllStudies()
      ]);
      setFolders(freshFolders);
      setSavedStudies(freshStudies);

      if (currentStudyId && studiesToDelete.some(s => s.id === currentStudyId)) {
        handleNewStudy();
      }
    } catch (e) {
      console.error("Delete folder failed", e);
    }
  };

  const handleMoveStudyToFolder = async (studyId: string, folderId?: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    try {
      await saveStudyToDB({ ...study, folderId });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);
    } catch (e) {
      console.error("Move to folder failed", e);
    }
  };

  const handleToggleStudyFinished = async (studyId: string) => {
    const study = savedStudies.find(s => s.id === studyId);
    if (!study) return;

    const nextStatus = !study.isFinished;

    try {
      await saveStudyToDB({ ...study, isFinished: nextStatus });
      const freshStudies = await getAllStudies();
      setSavedStudies(freshStudies);

      if (currentStudyId === studyId) {
        setIsFinished(nextStatus);
      }
    } catch (e) {
      console.error("Toggle finished failed", e);
    }
  };

  // Export/Import Logic
  const handleExportStudy = (study: SavedStudy) => {
    const dataStr = JSON.stringify(study, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${study.name.replace(/\s+/g, '_')}_RCM_Analysis.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleExportFolder = (folder: Folder) => {
    const folderStudies = savedStudies.filter(s => s.folderId === folder.id);
    const bundle = {
      type: 'folder_bundle',
      folder: folder,
      studies: folderStudies
    };
    const dataStr = JSON.stringify(bundle, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${folder.name.replace(/\s+/g, '_')}_RCM_Bundle.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleImportStudy = async (file: File) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const content = e.target?.result as string;
        const importedData = JSON.parse(content);

        if (importedData.type === 'folder_bundle') {
          const newFolderId = `folder-imported-${Date.now()}`;
          const newFolder: Folder = {
            ...importedData.folder,
            id: newFolderId,
            timestamp: Date.now()
          };

          await saveFolderToDB(newFolder);

          for (const study of importedData.studies) {
            const finalStudy: SavedStudy = {
              ...study,
              id: `study-imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
              timestamp: Date.now(),
              folderId: newFolderId
            };
            await saveStudyToDB(finalStudy);
          }

          const [freshFolders, freshStudies] = await Promise.all([
            getAllFolders(),
            getAllStudies()
          ]);
          setFolders(freshFolders);
          setSavedStudies(freshStudies);

        } else {
          const importedStudy = importedData as SavedStudy;
          if (!importedStudy.name || !importedStudy.items) {
            throw new Error("Invalid study format");
          }

          const finalStudy: SavedStudy = {
            ...importedStudy,
            id: `study-imported-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
            timestamp: Date.now(),
            folderId: undefined
          };

          await saveStudyToDB(finalStudy);
          const freshStudies = await getAllStudies();
          setSavedStudies(freshStudies);
          handleLoadStudy(finalStudy);
        }

      } catch (err) {
        console.error("Import failed", err);
        setError("Failed to import. Ensure the file is a valid RCM Pro JSON or Bundle.");
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      <WelcomeModal isOpen={showWelcome} onClose={handleCloseWelcome} />
      <SODReference isOpen={showSODReference} onClose={() => setShowSODReference(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <OperationalContextBuilder 
        isOpen={showContextBuilder} 
        onClose={() => setShowContextBuilder(false)} 
        onComplete={(builtContext) => setContextText(builtContext)} 
        onUndo={handleUndo} 
        canUndo={history.length > 0}
        language={selectedLanguage}
      />
      <DecisionLogicModal isOpen={showDecisionLogic} onClose={() => setShowDecisionLogic(false)} onUndo={handleUndo} canUndo={history.length > 0} />
      <AICopilot data={results} onUpdate={handleResultsUpdate} language={selectedLanguage} />

      {isSidebarOpen && <div className="fixed inset-0 bg-black/50 z-40 md:hidden animate-fade-in" onClick={() => setIsSidebarOpen(false)} />}

      <div className={`fixed md:static inset-y-0 left-0 z-50 w-72 transform transition-transform duration-300 ease-in-out shadow-lg md:shadow-none ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}`}>
        <Sidebar 
          studies={savedStudies} 
          folders={folders}
          currentStudyId={currentStudyId} 
          onSelect={handleLoadStudy} 
          onDelete={handleDeleteStudy} 
          onDuplicate={handleDuplicateStudy}
          onNew={handleNewStudy} 
          onNewFolder={handleNewFolder}
          onRenameFolder={handleRenameFolder}
          onDeleteFolder={handleDeleteFolder}
          onMoveStudy={handleMoveStudyToFolder}
          onExport={handleExportStudy}
          onExportFolder={handleExportFolder}
          onImport={handleImportStudy}
          onToggleFinished={handleToggleStudyFinished}
        />
      </div>

      <div className="flex-1 flex flex-col h-full overflow-hidden w-full relative">
        <header className="bg-white border-b border-slate-200 shrink-0 z-20 shadow-sm relative">
          <div className="h-20 px-6 flex items-center justify-between gap-4">
            <div className="flex items-center gap-6 min-w-0">
              <button className="p-2 -ml-2 text-slate-500 hover:bg-slate-100 rounded-lg md:hidden" onClick={() => setIsSidebarOpen(true)}><Menu size={24} /></button>
              <div className="hidden lg:flex items-center gap-4 pr-6 border-r border-slate-100 group text-nowrap">
                <div className="p-2.5 bg-slate-900 rounded-[1.2rem] text-white shadow-2xl shadow-indigo-100 ring-2 ring-indigo-50/50 group-hover:bg-indigo-600 transition-all duration-500 group-hover:-rotate-6"><Cpu size={22} className="text-indigo-400 group-hover:text-white" /></div>
                <div className="flex flex-col"><span className="text-lg font-black tracking-tighter text-slate-900 leading-none">RCM</span><div className="flex items-center gap-1 mt-1"><span className="text-[11px] font-black tracking-[0.25em] text-indigo-600 leading-none">GENERATOR</span><span className="text-[11px] font-black text-slate-400 leading-none">PRO</span></div></div>
              </div>
              <div className="flex flex-col min-w-0">
                 <div className="flex items-center gap-2">
                   <input type="text" value={studyName} onChange={(e) => setStudyName(e.target.value)} placeholder="Untitled Analysis" className="text-lg font-black text-slate-800 bg-transparent border-b-2 border-transparent hover:border-slate-200 focus:border-indigo-500 focus:outline-none transition-all w-full sm:w-80 truncate" />
                   {isFinished && (
                     <div className="flex items-center gap-1.5 px-2 py-0.5 bg-emerald-50 text-emerald-600 border border-emerald-100 rounded-md animate-in zoom-in-95">
                        <CheckCircle2 size={12} fill="currentColor" className="fill-emerald-600/20" />
                        <span className="text-[9px] font-black uppercase tracking-widest">Finished</span>
                     </div>
                   )}
                 </div>
                 <p className="hidden sm:block text-[10px] text-slate-400 font-black uppercase tracking-[0.15em] mt-1">{currentStudyId ? "System Repository" : "Temporary Workspace"}</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              {/* Language Picker */}
              <div className="hidden xl:flex items-center gap-2 mr-4 bg-slate-50 border border-slate-200 px-3 py-1.5 rounded-xl">
                 <Globe size={14} className="text-indigo-600" />
                 <select 
                   value={selectedLanguage}
                   onChange={(e) => setSelectedLanguage(e.target.value)}
                   className="bg-transparent text-[10px] font-black uppercase tracking-widest text-slate-700 outline-none cursor-pointer"
                 >
                   {LANGUAGES.map(lang => (
                     <option key={lang.code} value={lang.code}>{lang.flag} {lang.label}</option>
                   ))}
                 </select>
              </div>

              <div className="hidden lg:flex items-center gap-2 pr-3 mr-1">
                <button onClick={() => setShowSODReference(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><BookOpen size={16} />S/O/D Guide</button>
                <button onClick={() => setShowDecisionLogic(true)} className="flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-emerald-600 hover:bg-emerald-50 rounded-xl transition-all font-bold text-xs uppercase tracking-tight"><GitBranch size={16} />Logic Tree</button>
              </div>
              <div className="hidden sm:flex items-center text-[10px] font-black uppercase tracking-widest transition-opacity duration-300 mr-2">{justSaved ? (<span className="text-emerald-600 flex items-center gap-1.5 font-bold animate-pulse"><Check size={14} strokeWidth={3} /> Synced</span>) : (<span className="text-slate-300">{results ? 'Local draft' : ''}</span>)}</div>
              <div className="flex items-center gap-2">
                <button onClick={handleUndo} disabled={history.length === 0} className={`p-2.5 rounded-xl transition-all ${history.length > 0 ? 'bg-slate-100 text-slate-700 hover:bg-slate-200 shadow-sm' : 'text-slate-200 cursor-not-allowed'}`} title="Undo last action"><Undo2 size={20} /></button>
                <button onClick={() => handleSaveStudy(false)} disabled={!results && !contextText} className={`flex items-center gap-3 px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl ${justSaved ? 'bg-emerald-600 text-white border-emerald-600 shadow-emerald-200 scale-[1.02]' : 'bg-indigo-600 text-white hover:bg-indigo-700 active:scale-95 shadow-indigo-100 hover:shadow-indigo-200'} ${(!results && !contextText) ? 'opacity-30 cursor-not-allowed' : ''}`}>
                   {justSaved ? <Check size={18} /> : <Save size={18} />}
                   <span className="hidden sm:inline">{justSaved ? "Analysis Saved" : "Save Study"}</span>
                </button>
              </div>
            </div>
          </div>
        </header>

        <main className="flex-1 overflow-y-auto p-4 sm:px-6 bg-slate-50/50">
          <div className="w-full px-2 py-6">
            {!results && (
              <div className="mb-8 text-center sm:text-left animate-in slide-in-from-bottom-4 duration-500 max-w-7xl mx-auto">
                <h2 className="text-3xl font-black text-slate-900 mb-3 tracking-tighter uppercase">Generate Maintenance Strategies</h2>
                <p className="text-slate-500 max-w-2xl text-lg leading-relaxed font-medium italic opacity-70">Provide operational context to generate a comprehensive Reliability Centered Maintenance analysis based on SAE JA1011 standards.</p>
              </div>
            )}
            <div className={`bg-white rounded-[2rem] shadow-sm border border-slate-200 overflow-hidden mb-10 transition-all duration-300 ${!results ? 'max-w-7xl mx-auto' : ''}`}>
              <div className="border-b border-slate-100 bg-slate-50/50 px-8 pt-5 flex gap-8 overflow-x-auto">
                <button onClick={() => setActiveTab('manual')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'manual' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Type size={14} />Manual Synthesis</button>
                <button onClick={() => setActiveTab('upload')} className={`pb-5 text-[11px] font-black uppercase tracking-[0.2em] border-b-2 transition-all flex items-center gap-2.5 ${activeTab === 'upload' ? 'border-indigo-600 text-indigo-600' : 'border-transparent text-slate-400 hover:text-slate-600'}`}><Upload size={14} />Knowledge Upload</button>
              </div>
              <div className="p-8">
                {activeTab === 'manual' && (
                  <div className="space-y-5 animate-fade-in">
                    <div className="flex justify-between items-center"><label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest">Operational Context Description ({selectedLanguage})</label><button onClick={() => setShowContextBuilder(true)} className="group relative flex items-center gap-2.5 px-6 py-2.5 overflow-hidden rounded-[1.2rem] transition-all duration-300 active:scale-95 shadow-lg hover:shadow-indigo-500/20"><div className="absolute inset-0 bg-gradient-to-r from-indigo-600 via-violet-600 to-indigo-600 bg-[length:200%_auto] animate-[gradient_3s_linear_infinite] group-hover:scale-105 transition-transform duration-500"></div><div className="relative flex items-center gap-2"><div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-md"><Sparkles size={16} className="text-white fill-white animate-pulse" /></div><span className="text-[11px] font-black text-white uppercase tracking-[0.1em]">Open Context Wizard</span></div></button></div>
                    <textarea className="w-full h-56 p-6 bg-slate-50 border border-slate-200 rounded-[2rem] focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all resize-none text-slate-800 placeholder:text-slate-300 font-medium shadow-inner" placeholder={`e.g., Centrifugal Pump P-101 is critical for line availability... (Enter details in ${selectedLanguage})`} value={contextText} onChange={(e) => setContextText(e.target.value)} />
                  </div>
                )}
                {activeTab === 'upload' && (
                  <div className="space-y-4 animate-fade-in">
                     <div className="border-2 border-dashed border-slate-200 rounded-[2.5rem] p-12 flex flex-col items-center justify-center bg-slate-50 hover:bg-indigo-50/30 transition-all cursor-pointer relative group"><input type="file" id="file-upload" className="absolute inset-0 w-full h-full opacity-0 cursor-pointer" accept=".txt,.pdf,.png,.jpg,.jpeg,.docx" onChange={handleFileUpload} />{!fileData ? (<><div className="w-16 h-16 bg-white shadow-xl text-indigo-600 rounded-[1.5rem] flex items-center justify-center mb-6 group-hover:scale-110 group-hover:bg-indigo-600 group-hover:text-white transition-all duration-500"><Upload size={28} /></div><p className="text-xs font-black uppercase tracking-widest text-slate-400">Click to upload technical documentation</p><p className="text-[10px] text-slate-300 mt-2 font-bold italic">Supports PDF, DOCX, TXT and Images</p></>) : (<div className="flex items-center gap-5 w-full max-md p-6 bg-white rounded-[2rem] shadow-2xl border border-indigo-100 z-10 animate-in zoom-in-95"><div className="p-4 bg-emerald-50 text-emerald-500 rounded-2xl shadow-inner"><FileCheck size={28} /></div><div className="flex-1 min-w-0"><p className="text-sm font-black text-slate-900 truncate tracking-tight">{fileData.name}</p><p className="text-[10px] font-bold text-slate-400 uppercase tracking-tighter mt-1">Ready for Analysis</p></div><button onClick={(e) => { e.preventDefault(); clearFile(); }} className="p-3 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 size={20} /></button></div>)}</div>
                     {fileData && (
                       <div className="flex justify-center mt-6">
                         <button 
                           onClick={handleExtractContext} 
                           disabled={isExtracting}
                           className={`flex items-center gap-3 px-8 py-3 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all shadow-xl active:scale-95 ${isExtracting ? 'bg-indigo-400 text-white cursor-wait' : 'bg-white text-indigo-600 border border-indigo-100 hover:bg-indigo-50 shadow-indigo-100/50'}`}
                         >
                           {isExtracting ? <Loader2 size={16} className="animate-spin" /> : <FileSearch size={16} />}
                           {isExtracting ? `Synthesizing in ${selectedLanguage}...` : `Extract & Structure in ${selectedLanguage}`}
                         </button>
                       </div>
                     )}
                  </div>
                )}
                {error && (<div className="mt-6 p-5 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-[11px] font-black uppercase tracking-widest flex items-center gap-3 animate-in shake-in-from-right duration-500"><AlertTriangle size={18} />{error}</div>)}
                <div className="mt-8 flex flex-col sm:flex-row justify-end items-center gap-4">{results && results.length > 0 && (<label className="flex items-center gap-3 px-4 py-2 bg-slate-50 border border-slate-200 rounded-xl cursor-pointer hover:bg-white transition-all"><input type="checkbox" checked={isMerging} onChange={(e) => setIsMerging(e.target.checked)} className="w-4 h-4 text-indigo-600 rounded border-slate-300 focus:ring-indigo-500" /><span className="text-xs font-bold text-slate-600 uppercase tracking-tight">Merge with existing items</span></label>)}<button onClick={handleGenerate} disabled={isLoading || isExtracting} className={`flex items-center gap-3 px-10 py-4 rounded-2xl text-[11px] font-black uppercase tracking-[0.2em] text-white shadow-2xl transition-all active:scale-95 ${isLoading ? 'bg-indigo-400 shadow-none' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200 shadow-indigo-300 hover:shadow-indigo-300 hover:-translate-y-1'} ${(isLoading || isExtracting) ? 'opacity-50' : ''}`}>{isLoading ? <Loader2 size={20} className="animate-spin" /> : (isMerging ? <PlusCircle size={20} /> : <Zap size={20} className="fill-white" />)}{isLoading ? "Running Intelligence Engine..." : (isMerging ? "Append New Insights" : "Initiate RCM Analysis")}</button></div>
              </div>
            </div>
            {results && <AnalysisResult data={results} studyName={studyName} onUpdate={handleResultsUpdate} onUndo={handleUndo} canUndo={history.length > 0} language={selectedLanguage} />}
          </div>
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { RCMItem, InspectionSheet, InspectionStep, ConsequenceCategory, ComponentIntel } from '../types';
import { generateInspectionSheet, generateComponentIntel, validateRCMAnalysis } from '../services/geminiService';
import { IntervalOptimizerModal } from './IntervalOptimizerModal';
import { CMMSBridgeModal } from './CMMSBridgeModal';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip as RechartsTooltip, Cell 
} from 'recharts';
import { 
  AlertTriangle, CheckCircle, Clock, Activity, FileText, 
  Pencil, Trash2, Save, X, ClipboardList, Loader2,
  FileCheck, File, Printer, AlertOctagon, FilterX, User, ShieldAlert, Wrench, Search, ChevronRight, Sparkles, RefreshCw,
  ArrowUpDown, ArrowUp, ArrowDown, Filter, Plus, Tag, ShieldCheck, Zap, ListChecks, Info, MapPin, Eye, Undo2, Target, Palette, Image as ImageIcon, Box, Layers, UserPlus, Copy, LayoutList, Download, ShieldX
} from 'lucide-react';

interface AnalysisResultProps {
  data: RCMItem[];
  studyName: string;
  onUpdate: (newData: RCMItem[]) => void;
  onUndo: () => void;
  canUndo: boolean;
  language: string;
}

const CONSEQUENCE_LABELS: ConsequenceCategory[] = [
  'Hidden - Safety/Env', 
  'Hidden - Operational', 
  'Evident - Safety/Env', 
  'Evident - Operational',
  'Evident - Non-Operational'
];

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

const getScoreColor = (score: number) => {
  if (score >= 8) return 'text-red-600 font-bold';
  if (score >= 5) return 'text-amber-600 font-medium';
  return 'text-slate-500';
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, studyName, onUpdate, onUndo, canUndo, language }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);

  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet'; direction: 'asc' | 'desc' }>({ key: 'functionType', direction: 'asc' });
  const [searchFilters, setSearchFilters] = useState({
    component: '',
    functionType: '',
    function: '',
    failureMode: '',
    consequenceCategory: '',
    iso14224Code: ''
  });

  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [isValidating, setIsValidating] = useState(false);
  const [generatingIntelIds, setGeneratingIntelIds] = useState<Set<string>>(new Set());
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);
  const [optimizingItem, setOptimizingItem] = useState<RCMItem | null>(null);
  const [showCMMSBridge, setShowCMMSBridge] = useState(false);
  const [isExtracting, setIsExtracting] = useState(false);

  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => item !== null && item !== undefined);

    if (matrixFilter) {
      result = result.filter(item => 
        (item.severity || 0) === matrixFilter.s && 
        (item.occurrence || 0) === matrixFilter.o
      );
    }

    if (barFilter) {
      result = result.filter(item => item.id === barFilter);
    }

    if (searchFilters.component) {
      result = result.filter(item => (item.component || '').toLowerCase().includes(searchFilters.component.toLowerCase()));
    }
    if (searchFilters.functionType) {
      result = result.filter(item => (item.functionType || '').toLowerCase() === searchFilters.functionType.toLowerCase());
    }
    if (searchFilters.function) {
      result = result.filter(item => (item.function || '').toLowerCase().includes(searchFilters.function.toLowerCase()));
    }
    if (searchFilters.failureMode) {
      result = result.filter(item => (item.failureMode || '').toLowerCase().includes(searchFilters.failureMode.toLowerCase()));
    }
    if (searchFilters.consequenceCategory) {
      result = result.filter(item => (item.consequenceCategory || '').toLowerCase().includes(searchFilters.consequenceCategory.toLowerCase()));
    }
    if (searchFilters.iso14224Code) {
      result = result.filter(item => (item.iso14224Code || '').toLowerCase().includes(searchFilters.iso14224Code.toLowerCase()));
    }

    result.sort((a, b) => {
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;

      // Hierarchy: FunctionType > FunctionName > FF > Component > FailureMode
      const secondarySort = (x: RCMItem, y: RCMItem) => {
        const ft = (x.functionType || '').localeCompare(y.functionType || '');
        if (ft !== 0) return ft;
        const f = (x.function || '').localeCompare(y.function || '');
        if (f !== 0) return f;
        const ff = (x.functionalFailure || '').localeCompare(y.functionalFailure || '');
        if (ff !== 0) return ff;
        const comp = (x.component || '').localeCompare(y.component || '');
        if (comp !== 0) return comp;
        return (x.failureMode || '').localeCompare(y.failureMode || '');
      };

      if (sortConfig.key === 'status_color') {
        const aVal = (a.isNew ? 1 : 0) * 1000 + (a.rpn || 0);
        const bVal = (b.isNew ? 1 : 0) * 1000 + (b.rpn || 0);
        if (aVal === bVal) return secondarySort(a, b);
        return (bVal - aVal) * multiplier;
      }

      if (sortConfig.key === 'inspectionSheet') {
        const aHas = a.inspectionSheet ? 1 : 0;
        const bHas = b.inspectionSheet ? 1 : 0;
        if (aHas === bHas) return secondarySort(a, b);
        return (aHas - bHas) * multiplier;
      }

      const aVal = a[sortConfig.key as keyof RCMItem];
      const bVal = b[sortConfig.key as keyof RCMItem];

      if (aVal === bVal) return secondarySort(a, b);
      if (aVal === undefined || aVal === null) return 1;
      if (bVal === undefined || bVal === null) return -1;

      if (typeof aVal === 'string' && typeof bVal === 'string') {
        return aVal.localeCompare(bVal) * multiplier;
      }
      return ((aVal as number) - (bVal as number)) * multiplier;
    });

    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  const handleInternalUndo = () => {
    onUndo();
    setTimeout(() => {
       if (viewSheet) {
          const updatedItem = data.find(i => i.id === viewSheet.item.id);
          if (updatedItem) setViewSheet({ item: updatedItem });
       }
       if (selectedIntel) {
          const updatedItem = data.find(i => i.id === selectedIntel.id);
          if (updatedItem) setSelectedIntel(updatedItem);
       }
    }, 0);
  };

  const requestSort = (key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') {
      direction = 'desc';
    } else if (key === 'rpn' || key === 'status_color' || key === 'inspectionSheet') {
      direction = 'desc';
    }
    setSortConfig({ key, direction });
  };

  const handleSearchChange = (field: keyof typeof searchFilters, value: string) => {
    setSearchFilters(prev => ({ ...prev, [field]: value }));
  };

  const handleDelete = (id: string) => {
    const newData = data.filter(item => item.id !== id);
    onUpdate(newData);
    if (viewSheet?.item.id === id) setViewSheet(null);
  };

  const handleEdit = (item: RCMItem) => {
    setEditingId(item.id);
    setEditForm({ ...item });
  };

  const handleCancel = () => {
    setEditingId(null);
    setEditForm(null);
  };

  const handleSave = async () => {
    if (!editForm || !editingId) return;
    const originalItem = data.find(d => d.id === editingId);
    if (!originalItem) return;
    const hasCriticalChanges = 
      editForm.maintenanceTask !== originalItem.maintenanceTask ||
      editForm.failureMode !== originalItem.failureMode ||
      editForm.component !== originalItem.component;
    const needsRegeneration = hasCriticalChanges && !!originalItem.inspectionSheet;
    const updatedForm = {
       ...editForm,
       rpn: (editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1),
       inspectionSheet: needsRegeneration ? undefined : editForm.inspectionSheet,
       isNew: false
    };
    const newData = data.map(item => item.id === editingId ? updatedForm : item);
    onUpdate(newData);
    setEditingId(null);
    setEditForm(null);
    if (needsRegeneration) {
      setRegeneratingIds(prev => new Set(prev).add(updatedForm.id));
      try {
        const newSheet = await generateInspectionSheet(updatedForm, language);
        const finalData = newData.map(item => 
          item.id === updatedForm.id ? { ...item, inspectionSheet: newSheet } : item
        );
        onUpdate(finalData);
      } catch (err) { console.error("Failed to auto-regenerate sheet", err); } finally {
        setRegeneratingIds(prev => {
          const next = new Set(prev);
          next.delete(updatedForm.id);
          return next;
        });
      }
    }
  };

  const handleChange = (field: keyof RCMItem, value: any) => {
    if (!editForm) return;
    setEditForm({ ...editForm, [field]: value });
  };

  const handleGenerateAllSheets = async () => {
    const itemsToProcess = data.filter(item => !item.inspectionSheet);
    if (itemsToProcess.length === 0) {
      alert("All items already have inspection sheets generated.");
      return;
    }
    setGeneratingSheets(true);
    setProgress({ current: 0, total: itemsToProcess.length });
    let currentData = [...data];
    const BATCH_SIZE = 3;
    for (let i = 0; i < itemsToProcess.length; i += BATCH_SIZE) {
      const batch = itemsToProcess.slice(i, i + BATCH_SIZE);
      await Promise.all(batch.map(async (item) => {
        try {
          const sheet = await generateInspectionSheet(item, language);
          const index = currentData.findIndex(d => d.id === item.id);
          if (index !== -1) currentData[index] = { ...currentData[index], inspectionSheet: sheet };
        } catch (e) { console.error(e); }
      }));
      setProgress(prev => ({ ...prev, current: Math.min(prev.total, i + BATCH_SIZE) }));
      onUpdate([...currentData]);
    }
    setGeneratingSheets(false);
  };

  const handleValidateLogic = async () => {
    if (data.length === 0) return;
    setIsValidating(true);
    try {
      const issues = await validateRCMAnalysis(data, language);
      const newData = data.map(item => {
        const match = issues.find(issue => issue.id === item.id);
        return { ...item, validationIssues: match ? match.issues : [] };
      });
      onUpdate(newData);
    } catch (e) {
      console.error(e);
      alert("Logic validation engine failed. Please try again.");
    } finally {
      setIsValidating(false);
    }
  };

  const handleIntelClick = async (item: RCMItem) => {
    if (item.componentIntel && item.componentIntel.description) {
      setSelectedIntel(item);
      return;
    }

    setGeneratingIntelIds(prev => new Set(prev).add(item.id));
    try {
      const intel = await generateComponentIntel(item.component, language);
      const newItem = { ...item, componentIntel: intel };
      const newData = data.map(d => d.id === item.id ? newItem : d);
      onUpdate(newData);
      setSelectedIntel(newItem);
    } catch (e) {
      console.error(e);
      alert("Failed to synthesize component metadata.");
    } finally {
      setGeneratingIntelIds(prev => {
        const next = new Set(prev);
        next.delete(item.id);
        return next;
      });
    }
  };

  const handleGenerateSingleSheet = async (item: RCMItem) => {
    setRegeneratingIds(prev => new Set(prev).add(item.id));
    try {
      const sheet = await generateInspectionSheet(item, language);
      const newData = data.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d);
      onUpdate(newData);
      const updatedItem = newData.find(d => d.id === item.id);
      if (updatedItem) setViewSheet({ item: updatedItem });
    } catch (e) { 
      alert("Failed to generate."); 
    } finally { 
      setRegeneratingIds(prev => {
        const next = new Set(prev);
        next.delete(item.id);
        return next;
      });
    }
  };

  const handleApplyOptimizedInterval = (newInterval: string) => {
    if (!optimizingItem) return;
    const newData = data.map(d => d.id === optimizingItem.id ? { ...d, interval: newInterval } : d);
    onUpdate(newData);
    setOptimizingItem(null);
  };

  const updateItemInMainData = (updatedItem: RCMItem) => {
    const newData = data.map(d => d.id === updatedItem.id ? updatedItem : d);
    onUpdate(newData);
  };

  const handleDeleteStep = (idx: number) => {
    if (!viewSheet) return;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet;
    if (!sheet || !sheet.steps) return;
    const newSteps = sheet.steps.filter((_, i) => i !== idx).map((s, i) => ({ ...s, step: i + 1 }));
    const updatedItem = { ...item, inspectionSheet: { ...sheet, steps: newSteps } };
    setViewSheet({ item: updatedItem });
    updateItemInMainData(updatedItem);
  };

  const handleAddStep = () => {
    if (!viewSheet) return;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet || { responsibility: 'Operator', estimatedTime: '10m', safetyPrecautions: 'Standard PPE', toolsRequired: 'None', steps: [] };
    const newStep: InspectionStep = {
      step: (sheet.steps?.length || 0) + 1,
      description: 'New inspection action',
      criteria: 'Pass/Fail criteria',
      technique: 'Visual'
    };
    const updatedItem = { ...item, inspectionSheet: { ...sheet, steps: [...(sheet.steps || []), newStep] } };
    setViewSheet({ item: updatedItem });
    updateItemInMainData(updatedItem);
    setEditingStepIdx((sheet.steps?.length || 0));
  };

  const handleUpdateStepField = (idx: number, field: keyof InspectionStep, value: string | number) => {
    if (!viewSheet) return;
    const item = viewSheet.item;
    const sheet = item.inspectionSheet;
    if (!sheet || !sheet.steps) return;
    const newSteps = [...sheet.steps];
    newSteps[idx] = { ...newSteps[idx], [field]: value };
    const updatedItem = { ...item, inspectionSheet: { ...sheet, steps: newSteps } };
    setViewSheet({ item: updatedItem });
    updateItemInMainData(updatedItem);
  };

  const handleExcelTechnicalExtract = () => {
    setIsExtracting(true);
    const headers = [
      "Function", 
      "Functional failure", 
      "Component", 
      "Component Description",
      "Failure mode", 
      "ISO 14224 Code",
      "Proposed Task", 
      "Frequency",
      "Step", 
      "Action",
      "Responsibility",
      "Duration",
      "Acceptance Criteria"
    ];

    const rows: string[] = [];

    let lastFunc = "";
    let lastFF = "";
    let lastComp = "";
    let lastFM = "";

    // Sort by RCM hierarchy for the export but use filtered data to respect active search/filters
    const sortedForExport = [...processedData].sort((a, b) => {
        const ft = (a.functionType || '').localeCompare(b.functionType || '');
        if (ft !== 0) return ft;
        const f = (a.function || '').localeCompare(b.function || '');
        if (f !== 0) return f;
        const ff = (a.functionalFailure || '').localeCompare(b.functionalFailure || '');
        if (ff !== 0) return ff;
        const comp = (a.component || '').localeCompare(b.component || '');
        if (comp !== 0) return comp;
        return (a.failureMode || '').localeCompare(b.failureMode || '');
    });

    sortedForExport.forEach(item => {
      const steps = item.inspectionSheet?.steps || [];
      const responsibility = item.inspectionSheet?.responsibility || "";
      const duration = item.inspectionSheet?.estimatedTime || "";

      // Logic to detect if we should show header cells or keep them empty (Classical RCM sheet style)
      const showFunc = item.function !== lastFunc;
      const showFF = showFunc || item.functionalFailure !== lastFF;
      const showComp = showFF || item.component !== lastComp;
      const showFM = showComp || item.failureMode !== lastFM;

      // Update state for next item
      lastFunc = item.function;
      lastFF = item.functionalFailure;
      lastComp = item.component;
      lastFM = item.failureMode;

      const metadataCols = [
        showFunc ? item.function : "",
        showFF ? item.functionalFailure : "",
        showComp ? item.component : "",
        showComp ? (item.componentIntel?.description || "") : "",
        showFM ? item.failureMode : "",
        showFM ? item.iso14224Code : ""
      ];

      if (steps.length > 0) {
        steps.forEach((step, idx) => {
          // Task and Frequency only show on the first step of this task
          const taskInfo = idx === 0 ? [item.maintenanceTask, item.interval] : ["", ""];
          // Header info (Function -> FM) only show on the first step of the first task of this FM
          const headerInfo = (idx === 0 && showFM) ? metadataCols : ["", "", "", "", "", ""];

          const rowData = [
            ...headerInfo,
            ...taskInfo,
            step.step,
            step.description,
            idx === 0 ? responsibility : "",
            idx === 0 ? duration : "",
            step.criteria
          ];

          rows.push(rowData.map(v => `"${String(v || '').replace(/"/g, '""')}"`).join(","));
        });
      } else {
        // Fallback for items without inspection sheets
        const rowData = [
          showFM ? item.function : "",
          showFF ? item.functionalFailure : "",
          showComp ? item.component : "",
          showComp ? (item.componentIntel?.description || "") : "",
          showFM ? item.failureMode : "",
          showFM ? item.iso14224Code : "",
          item.maintenanceTask,
          item.interval,
          "", "", "", "", ""
        ];
        rows.push(rowData.map(v => `"${String(v || '').replace(/"/g, '""')}"`).join(","));
      }
    });

    const csvContent = "\uFEFFsep=,\n" + [headers.join(","), ...rows].join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.setAttribute('href', url);

    // Use the studyName for the filename as requested
    const fileNameBase = studyName ? studyName.trim().replace(/\s+/g, '_') : 'RCM_Decision_Sheet';
    link.setAttribute('download', `${fileNameBase}_Decision_Sheet.csv`);

    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);

    setTimeout(() => setIsExtracting(false), 1500);
  };

  const handleMatrixClick = (s: number, o: number) => {
    if (matrixFilter?.s === s && matrixFilter?.o === o) {
      setMatrixFilter(null);
    } else {
      setMatrixFilter({ s, o });
