import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  X, Send, Sparkles, ChevronDown, 
  Plus, CheckCircle2, Search, 
  UserCheck, ShieldAlert, Zap, Loader2, LayoutGrid, 
  ChevronRight, RotateCcw, Target, Info, AlertTriangle, Wrench
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
  language: string;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
  isFacilitatorInsight?: boolean;
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model'; isFacilitator?: boolean }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        const isQuestion = cleanLine.endsWith('?');

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className={`flex-1 text-[13px] font-medium leading-relaxed ${isQuestion ? 'text-indigo-700 font-bold italic' : ''}`}>
                {cleanLine.replace(/^[*|-]\s*/, '')}
              </span>
            </div>
          );
        }

        return (
          <p key={idx} className={`leading-relaxed text-[13px] font-medium ${isQuestion && role === 'model' ? 'bg-indigo-50 p-2 rounded-lg border-l-4 border-indigo-600 text-indigo-900 shadow-sm' : ''}`}>
            {cleanLine}
          </p>
        );
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate, language }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [isOpen, messages]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object') {
            proposals.push({
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              type: a.type || 'ADD',
              reason: a.reason || 'Facilitator recommendation.',
              item: a.item || {},
              applied: false
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse MIRA action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleFacilitatorAudit = async () => {
    if (!data || data.length === 0) return;
    setIsLoading(true);
    setIsOpen(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const studySummary = data.map(i => ({
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        rpn: i.rpn
      }));

      const prompt = `
        CURRENT STUDY: ${JSON.stringify(studySummary)}
        TARGET LANGUAGE: ${language}

        TASK:
        Perform a technical Facilitator Audit in ${language}. You are MIRA. 
        Focus on:
        1. Human-Factor risks.
        2. Strategic gaps.
        3. Reliability improvements.

        MANDATORY RESPONSE FORMAT:
        - Conversational text in ${language}.
        - If suggesting a record, include <ACTION> JSON with technical descriptions in ${language}.

        STRICT JSON RULES:
        - JSON KEYS MUST REMAIN IN ENGLISH.
        - Every "ADD" action MUST include a complete RCM hierarchy: function, functionalFailure, component, failureMode, maintenanceTask, etc.
        - JSON "taskType" MUST be one of: 'Condition Monitoring', 'Time-Based', 'Run-to-Failure', 'Redesign', 'Failure Finding', 'Lubrication', 'Servicing', 'Restoration', 'Replacement', 'Training', 'Procedural Change'.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: `You are MIRA, the Facilitator. You respond in ${language}. You wrap suggestions in <ACTION> JSON tags.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Audit results generated.", proposals, isFacilitatorInsight: true }]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        CURRENT STUDY DATA (LAST 15): ${JSON.stringify((data || []).slice(-15).map(i => ({ comp: i.component, fail: i.failureMode, task: i.maintenanceTask }))}
        USER SUGGESTION: "${userMsg}"
        TARGET LANGUAGE: ${language}

        FACILITATOR INSTRUCTIONS:
        1. Act as MIRA. Respond in ${language}.
        2. If suggesting changes, SYNTHESIZE full technical records. Descriptions/tasks must be in ${language}.
        3. Every addition MUST be a complete JSON object in <ACTION> tags.
        4. MANDATORY: DO NOT TRANSLATE JSON KEYS.
        5. FOR NEW ITEMS (ADD), you MUST provide a valid 'function' and 'functionalFailure' that logically matches the component.
        6. REQUIRED FIELDS FOR NEW ITEMS: 
           - component, functionType (Primary/Secondary), function, functionalFailure, failureMode, failureEffect, consequenceCategory, iso14224Code (3-letter), severity, occurrence, detection, maintenanceTask, interval, taskType.
           - componentIntel: { description, location, visualCues }
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          systemInstruction: `You are MIRA. You communicate in ${language}. You provide technical actions in <ACTION> JSON tags.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Analysis complete.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Facilitator offline." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    const message = messages[messageIndex];
    if (!message || !message.proposals) return;

    const proposal = message.proposals.find(p => p.id === proposalId);
    if (!proposal || proposal.applied || !proposal.item) return;

    let newData = data ? [...data] : [];

    if (proposal.type === 'ADD') {
      const s = Number(proposal.item.severity) || 5;
      const o = Number(proposal.item.occurrence) || 3;
      const d = Number(proposal.item.detection) || 4;

      const newItem: RCMItem = {
        id: `rcm-mir-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
        component: proposal.item.component || 'Synthesized Component',
        functionType: (proposal.item.functionType as any) || 'Secondary',
        function: proposal.item.function || 'Technical function.',
        functionalFailure: proposal.item.functionalFailure || 'Operational loss.',
        failureMode: proposal.item.failureMode || 'Degradation mechanism.',
        failureEffect: proposal.item.failureEffect || 'Impact.',
        consequenceCategory: (proposal.item.consequenceCategory as ConsequenceCategory) || 'Evident - Operational',
        iso14224Code: proposal.item.iso14224Code || 'UNC',
        criticality: proposal.item.criticality as any || (s >= 8 ? 'High' : s >= 5 ? 'Medium' : 'Low'),
        severity: s,
        occurrence: o,
        detection: d,
        rpn: s * o * d,
        maintenanceTask: proposal.item.maintenanceTask || 'Inspection',
        interval: proposal.item.interval || 'Annually',
        taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
        componentIntel: {
          description: proposal.item.componentIntel?.description || 'Synchronized via MIRA.',
          location: proposal.item.componentIntel?.location || 'Asset location.',
          visualCues: proposal.item.componentIntel?.visualCues || 'Visual markers.'
        },
        isNew: true
      };
      newData.push(newItem);
    } 
    else if (proposal.type === 'UPDATE') {
      newData = newData.map(item => {
        const isMatch = proposal.item?.id ? item.id === proposal.item.id : (item.component === proposal.item?.component && item.failureMode === proposal.item?.failureMode);
        if (isMatch) {
          const updated = { ...item, ...proposal.item, isNew: false };
          updated.severity = Number(updated.severity) || item.severity;
          updated.occurrence = Number(updated.occurrence) || item.occurrence;
          updated.detection = Number(updated.detection) || item.detection;
          updated.rpn = updated.severity * updated.occurrence * updated.detection;
          return updated;
        }
        return item;
      });
    }

    onUpdate(newData);

    setMessages(prev => prev.map((m, idx) => {
      if (idx === messageIndex && m.proposals) {
        return {
          ...m,
          proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
        };
      }
      return m;
    }));
  };

  return (
    <div className="fixed bottom-6 right-6 z-50 flex flex-col items-end">
      {isOpen && (
        <div className="mb-4 w-[350px] sm:w-[520px] h-[700px] bg-white rounded-[3rem] shadow-[0_40px_100px_-20px_rgba(0,0,0,0.2)] border-2 border-slate-200 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-slate-900 p-6 text-white flex justify-between items-center shrink-0">
            <div className="flex items-center gap-4">
              <div className="p-2 bg-indigo-500/20 rounded-xl border border-indigo-400/30">
                <Sparkles size={18} className="text-indigo-400" />
              </div>
              <div>
                <h3 className="font-black text-xl tracking-tighter uppercase leading-none">MIRA <span className="text-[10px] text-indigo-400 tracking-widest ml-1">Facilitator</span></h3>
                <p className="text-[9px] text-slate-400 font-black uppercase tracking-[0.1em] mt-1">Facilitating in {language}</p>
              </div>
            </div>
            <button onClick={() => setIsOpen(false)} className="hover:bg-white/10 p-2 rounded-full transition-all"><ChevronDown size={28} /></button>
          </div>

          <div className="bg-indigo-50/50 px-6 py-3 border-b border-indigo-100 flex items-center justify-between gap-3 shrink-0">
             <div className="flex items-center gap-2 text-[10px] font-black text-indigo-600 uppercase tracking-widest">
               <ShieldAlert size={14} /> Audit ({language})
             </div>
             <button 
               onClick={handleFacilitatorAudit} 
               disabled={!data || data.length === 0 || isLoading}
               className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all disabled:opacity-30"
             >
               <Search size={12} /> Facilitate Audit
             </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-8 bg-slate-50/50 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center p-8 space-y-8">
                <div className="w-20 h-20 bg-white text-indigo-600 rounded-[2.2rem] flex items-center justify-center shadow-2xl border border-indigo-50"><UserCheck size={36} /></div>
                <div className="space-y-4">
                  <p className="text-xl font-black text-slate-900 tracking-tighter uppercase leading-tight">Ready to facilitate</p>
                  <p className="text-[13px] text-slate-500 font-medium italic">Communicating in {language}. I guide your study towards human RCM excellence.</p>
                </div>
              </div>
            )}

            {messages.map((m, i) => (
              <div key={i} className={`flex flex-col ${m.role === 'user' ? 'items-end' : 'items-start'} animate-in fade-in slide-in-from-bottom-4 duration-500`}>
                <div className={`max-w-[95%] p-5 rounded-[2rem] shadow-lg relative ${
                  m.role === 'user' 
                    ? 'bg-slate-900 text-white rounded-br-none font-bold text-[14px]' 
                    : 'bg-white text-slate-800 border-2 border-slate-100 rounded-bl-none shadow-slate-100/10'
                }`}>
                  <FormattedMessage text={m.text} role={m.role} isFacilitator={m.isFacilitatorInsight} />
                </div>

                {m.proposals && (
                  <div className="mt-6 w-full space-y-4">
                    {m.proposals.map((p) => (
                      <div key={p.id} className={`bg-white border-2 rounded-[2rem] p-6 shadow-xl relative overflow-hidden transition-all ${p.applied ? 'border-emerald-500 bg-emerald-50/30' : 'border-indigo-100 ring-4 ring-indigo-50/50'}`}>
                        <div className="flex justify-between items-start gap-4">
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center gap-2 mb-3">
                              <span className={`text-[9px] font-black uppercase tracking-[0.2em] px-2 py-0.5 rounded-full ${p.applied ? 'bg-emerald-500 text-white' : 'bg-indigo-600 text-white'}`}>
                                {p.applied ? 'Synced' : `${p.type} Request`}
                              </span>
                            </div>
                            <h5 className="text-sm font-black text-slate-900 uppercase truncate leading-none mb-3">{p.item?.component || 'New Item'}</h5>

                            {p.type === 'ADD' && (
                              <div className="space-y-3 mb-4">
                                <div className="flex items-start gap-2 group/field">
                                  <div className="mt-0.5 p-1 bg-amber-50 rounded text-amber-600 border border-amber-100 shrink-0">
                                    <AlertTriangle size={12} />
                                  </div>
                                  <div className="flex-1 min-w-0">
                                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-0.5">Failure Mode</span>
                                    <p className="text-[11px] font-bold text-slate-700 leading-tight uppercase tracking-tight">{p.item?.failureMode}</p>
                                  </div>
                                </div>
                                <div className="flex items-start gap-2 group/field">
                                  <div className="mt-0.5 p-1 bg-indigo-50 rounded text-indigo-600 border border-indigo-100 shrink-0">
                                    <Wrench size={12} />
                                  </div>
                                  <div className="flex-1 min-w-0">
                                    <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest block mb-0.5">Proposed Task</span>
                                    <p className="text-[11px] font-bold text-slate-700 leading-tight uppercase tracking-tight">{p.item?.maintenanceTask}</p>
                                  </div>
                                </div>
                              </div>
                            )}

                            <p className="text-[10px] font-bold text-slate-400 leading-tight italic border-t border-slate-50 pt-2">{p.reason}</p>
                          </div>
                          {!p.applied ? (
                             <button onClick={() => applySingleAction(p.id, i)} className="shrink-0 w-12 h-12 bg-indigo-600 text-white rounded-xl shadow-lg hover:bg-indigo-700 active:scale-90 transition-all flex items-center justify-center">
                               <Plus size={24} />
                             </button>
                          ) : (
                             <div className="shrink-0 w-12 h-12 bg-emerald-500 text-white rounded-xl shadow-lg flex items-center justify-center animate-in zoom-in">
                               <CheckCircle2 size={24} />
                             </div>
                          )}
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-white border border-slate-100 p-4 rounded-full flex items-center gap-3 shadow-sm">
                  <Loader2 size={16} className="animate-spin text-indigo-600" />
                  <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest italic">MIRA synthesizing in {language}...</span>
                </div>
              </div>
            )}
          </div>

          <div className="p-6 bg-white border-t border-slate-100 shrink-0">
            <div className="flex gap-4">
