import React, { useState, useRef, useEffect } from 'react';
import { GoogleGenAI } from "@google/genai";
import { RCMItem, ConsequenceCategory } from '../types';
import { 
  X, Send, Sparkles, ChevronDown, 
  Plus, CheckCircle2, Search, 
  UserCheck, ShieldAlert, Zap, Loader2, LayoutGrid, 
  ChevronRight, RotateCcw, Target, Info, AlertTriangle, Wrench, Box, Link2, Activity
} from 'lucide-react';

interface AICopilotProps {
  data: RCMItem[] | null;
  onUpdate: (newData: RCMItem[]) => void;
  language: string;
}

interface ProposedAction {
  id: string; 
  type: 'ADD' | 'UPDATE' | 'DELETE';
  item: Partial<RCMItem>;
  reason: string;
  applied?: boolean;
}

interface Message {
  role: 'user' | 'model';
  text: string;
  proposals?: ProposedAction[];
  isFacilitatorInsight?: boolean;
}

const FormattedMessage: React.FC<{ text: string; role: 'user' | 'model'; isFacilitator?: boolean }> = ({ text, role }) => {
  const lines = (text || '').split('\n');

  return (
    <div className={`space-y-2 ${role === 'model' ? 'text-slate-700' : 'text-white'}`}>
      {lines.map((line, idx) => {
        const trimmed = line.trim();
        const cleanLine = line.replace(/\*\*/g, '').replace(/#/g, '').trim();
        if (!cleanLine) return <div key={idx} className="h-2" />;

        const isQuestion = cleanLine.endsWith('?');

        if (trimmed.startsWith('* ') || trimmed.startsWith('- ')) {
          return (
            <div key={idx} className="flex gap-2 pl-2">
              <ChevronRight size={12} className={`shrink-0 mt-1 ${role === 'model' ? 'text-indigo-400' : 'text-white opacity-50'}`} />
              <span className={`flex-1 text-[13px] font-medium leading-relaxed ${isQuestion ? 'text-indigo-700 font-bold italic' : ''}`}>
                {cleanLine.replace(/^[*|-]\s*/, '')}
              </span>
            </div>
          );
        }

        return (
          <p key={idx} className={`leading-relaxed text-[13px] font-medium ${isQuestion && role === 'model' ? 'bg-indigo-50 p-2 rounded-lg border-l-4 border-indigo-600 text-indigo-900 shadow-sm' : ''}`}>
            {cleanLine}
          </p>
        );
      })}
    </div>
  );
};

export const AICopilot: React.FC<AICopilotProps> = ({ data, onUpdate, language }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);

  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isOpen && scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [isOpen, messages]);

  const parseAIResponse = (text: string): { cleanText: string, proposals?: ProposedAction[] } => {
    const actionRegex = /<ACTION>([\s\S]*?)<\/ACTION>/g;
    const proposals: ProposedAction[] = [];
    let cleanText = text;
    let match;

    while ((match = actionRegex.exec(text)) !== null) {
      try {
        const rawAction = JSON.parse(match[1]);
        const actions = Array.isArray(rawAction) ? rawAction : [rawAction];

        actions.forEach((a: any) => {
          if (a && typeof a === 'object') {
            proposals.push({
              id: `proposal-${Math.random().toString(36).substr(2, 9)}`,
              type: a.type || 'ADD',
              reason: a.reason || 'MIRA Synthesis Recommendation.',
              item: a.item || {},
              applied: false
            });
          }
        });

        cleanText = cleanText.replace(match[0], '');
      } catch (e) {
        console.error("Failed to parse MIRA action JSON", e);
      }
    }

    return { cleanText: cleanText.trim(), proposals: proposals.length > 0 ? proposals : undefined };
  };

  const handleFacilitatorAudit = async () => {
    if (!data || data.length === 0) return;
    setIsLoading(true);
    setIsOpen(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const studySummary = data.map(i => ({
        comp: i.component,
        fail: i.failureMode,
        task: i.maintenanceTask,
        rpn: i.rpn
      }));

      const prompt = `
        CURRENT STUDY SUMMARY: ${JSON.stringify(studySummary)}
        TARGET LANGUAGE: ${language}

        TASK:
        Perform an exhaustive RCM Facilitator Audit. Identify technical gaps, missing failure modes, or strategic logic errors.

        STRICT MIRA PROTOCOL:
        1. For any addition, return a complete SAE JA1011 technical record.
        2. Descriptions, functions, and tasks MUST be in ${language}.
        3. Use <ACTION> JSON tags. Keys must be in English.
        4. "ADD" item must include: component, functionType, function, functionalFailure, failureMode, failureEffect, consequenceCategory, severity, occurrence, detection, maintenanceTask, interval, taskType, iso14224Code, componentIntel.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          thinkingConfig: { thinkingBudget: 32768 },
          systemInstruction: `You are MIRA, the Lead RCM Facilitator. You synthesize strategy in ${language}. You provide complete RCM data records wrapped in <ACTION> tags.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Strategic audit complete.", proposals, isFacilitatorInsight: true }]);
    } catch (e) {
      console.error(e);
    } finally {
      setIsLoading(false);
    }
  };

  const handleSend = async () => {
    if (!input.trim() || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
      const prompt = `
        CURRENT STUDY CONTEXT: ${JSON.stringify((data || []).slice(-10).map(i => ({ c: i.component, fm: i.failureMode })))}
        USER REQUEST: "${userMsg}"
        TARGET LANGUAGE: ${language}

        MIRA SYNTHESIS TASK:
        1. If the user wants to add a component or failure mode, synthesize a high-fidelity RCM record.
        2. All technical content (Function, FF, Component, FM, Effect, Task) MUST be in ${language}.
        3. Wrap the synthesized record in <ACTION> JSON tags.
        4. MANDATORY JSON Keys (English): component, functionType, function, functionalFailure, failureMode, failureEffect, consequenceCategory, iso14224Code, severity, occurrence, detection, maintenanceTask, interval, taskType, componentIntel.
        5. Provide a short technical explanation in ${language} before the ACTION tags.
      `;

      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        config: {
          thinkingConfig: { thinkingBudget: 32768 },
          systemInstruction: `You are MIRA, an expert RCM Analyst. You help users add components to their analysis. You communicate in ${language} and provide data using <ACTION> JSON tags.`
        }
      });

      const { cleanText, proposals } = parseAIResponse(response.text || "");
      setMessages(prev => [...prev, { role: 'model', text: cleanText || "Synthesis complete.", proposals }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'model', text: "Facilitator offline." }]);
    } finally {
      setIsLoading(false);
    }
  };

  const applySingleAction = (proposalId: string, messageIndex: number) => {
    setMessages(prevMessages => {
      const message = prevMessages[messageIndex];
      if (!message || !message.proposals) return prevMessages;

      const proposal = message.proposals.find(p => p.id === proposalId);
      if (!proposal || proposal.applied || !proposal.item) return prevMessages;

      let newData = data ? [...data] : [];

      if (proposal.type === 'ADD') {
        const s = Number(proposal.item.severity) || 5;
        const o = Number(proposal.item.occurrence) || 3;
        const d = Number(proposal.item.detection) || 4;
        const rpn = s * o * d;

        const newItem: RCMItem = {
          id: `rcm-mir-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
          component: proposal.item.component || 'Synthesized Component',
          functionType: (proposal.item.functionType as any) || 'Primary',
          function: proposal.item.function || 'General asset function.',
          functionalFailure: proposal.item.functionalFailure || 'Partial loss of function.',
          failureMode: proposal.item.failureMode || 'Mechanical degradation.',
          failureEffect: proposal.item.failureEffect || 'Potential system downtime.',
          criticality: (proposal.item.criticality as any) || (rpn >= 100 ? 'High' : rpn >= 40 ? 'Medium' : 'Low'),
          consequenceCategory: (proposal.item.consequenceCategory as any) || 'Evident - Operational',
          iso14224Code: proposal.item.iso14224Code || 'OTH',
          severity: s,
          occurrence: o,
          detection: d,
          rpn: rpn,
          maintenanceTask: proposal.item.maintenanceTask || 'Inspection periodically.',
          interval: proposal.item.interval || 'Monthly',
          taskType: (proposal.item.taskType as any) || 'Condition Monitoring',
          componentIntel: proposal.item.componentIntel || {
            description: 'Synthesized via MIRA.',
            location: 'Asset assembly.',
            visualCues: 'Standard markers.'
          },
          isNew: true
        };
        newData.push(newItem);
      } 
      else if (proposal.type === 'UPDATE') {
        newData = newData.map(item => {
          const isMatch = proposal.item?.id ? item.id === proposal.item.id : (item.component === proposal.item?.component && item.failureMode === proposal.item?.failureMode);
          if (isMatch) {
            const updated = { ...item, ...proposal.item, isNew: false };
            updated.severity = Number(updated.severity) || item.severity;
            updated.occurrence = Number(updated.occurrence) || item.occurrence;
            updated.detection = Number(updated.detection) || item.detection;
            updated.rpn = updated.severity * updated.occurrence * updated.detection;
            return updated as RCMItem;
          }
          return item;
        });
      }

      onUpdate(newData);

      return prevMessages.map((m, idx) => {
        if (idx === messageIndex && m.proposals) {
          return {
            ...m,
            proposals: m.proposals.map(p => p.id === proposalId ? { ...p, applied: true } : p)
          };
        }
        return m;
      });
    });
  };

  return (
    <>
      <div className="fixed bottom-6 right-6 z-40 flex flex-col items-end gap-3 transition-all duration-500">
        <button 
          onClick={() => setIsOpen(!isOpen)}
          className={`flex items-center gap-3 p-4 sm:px-6 sm:py-4 rounded-[1.8rem] shadow-2xl transition-all active:scale-95 border ${isOpen ? 'bg-white text-slate-900 border-slate-100' : 'bg-indigo-600 text-white border-indigo-500 hover:bg-indigo-700'}`}
        >
          <div className={`p-2 rounded-xl ${isOpen ? 'bg-indigo-50 text-indigo-600' : 'bg-white/20'}`}>
            <Zap size={22} className={isOpen ? 'fill-indigo-600' : 'fill-white'} />
          </div>
          <span className="hidden sm:inline text-xs font-black uppercase tracking-widest">{isOpen ? 'Close MIRA' : 'Talk to MIRA'}</span>
        </button>
      </div>

      {isOpen && (
        <div className="fixed bottom-24 right-6 z-40 w-[calc(100vw-3rem)] sm:w-[28rem] h-[36rem] bg-white rounded-[2.5rem] shadow-2xl border border-slate-100 flex flex-col overflow-hidden animate-in slide-in-from-bottom-6 duration-500">
          <div className="bg-slate-900 p-6 flex justify-between items-center text-white shrink-0">
            <div className="flex items-center gap-4">
              <div className="p-3 bg-indigo-500/20 rounded-2xl border border-indigo-500/30">
                <Zap size={20} className="text-indigo-400 fill-indigo-400" />
              </div>
              <div>
                <h3 className="font-black text-lg tracking-tighter uppercase leading-none">MIRA Facilitator</h3>
                <p className="text-[10px] text-indigo-400 font-black uppercase tracking-widest mt-1">Maintenance Intelligence AI</p>
              </div>
            </div>
            <div className="flex gap-2">
              <button 
                onClick={() => setMessages([])}
                className="p-2 text-slate-500 hover:text-white transition-colors"
                title="Clear Chat"
              >
                <RotateCcw size={18} />
              </button>
              <button onClick={() => setIsOpen(false)} className="p-2 text-slate-500 hover:text-white transition-colors"><X size={20} /></button>
            </div>
          </div>

          <div className="bg-slate-50 border-b border-slate-100 px-6 py-3 flex justify-between items-center shrink-0">
             <div className="flex items-center gap-2 text-[9px] font-black text-slate-400 uppercase tracking-widest">
               <ShieldAlert size={14} className="text-indigo-600" /> Strategic Hub
             </div>
             <button 
               onClick={handleFacilitatorAudit}
               disabled={!data || data.length === 0 || isLoading}
               className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600 text-white rounded-xl text-[9px] font-black uppercase tracking-widest hover:bg-indigo-700 transition-all disabled:opacity-30 shadow-lg shadow-indigo-100"
             >
               <Sparkles size={12} /> Run Strategic Audit
             </button>
          </div>

          <div ref={scrollRef} className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/30 custom-scrollbar">
            {messages.length === 0 && (
              <div className="flex flex-col items-center justify-center h-full text-center space-y-4 opacity-50">
                <div className="p-6 bg-white rounded-[2rem] border border-slate-100 shadow-sm">
                  <LayoutGrid size={48} className="text-indigo-100" />
