                <div>
                  <p className="text-sm font-bold text-slate-800 uppercase tracking-tight">System Ready</p>
                  <p className="text-[10px] font-medium text-slate-400 uppercase tracking-widest mt-1">Ask MIRA to synthesize new failure modes</p>
                </div>
              </div>
            )}

            {messages.map((m, mIdx) => (
              <div key={mIdx} className={`flex flex-col gap-3 ${m.role === 'user' ? 'items-end' : 'items-start'}`}>
                <div className={`p-4 rounded-2xl shadow-sm text-sm font-medium ${m.role === 'user' ? 'bg-indigo-600 text-white rounded-tr-none' : 'bg-white text-slate-800 border border-slate-100 rounded-tl-none ring-1 ring-slate-50'}`}>
                  <FormattedMessage text={m.text} role={m.role} />
                </div>

                {m.proposals && m.proposals.length > 0 && (
                  <div className="w-full space-y-3 mt-1">
                    {m.proposals.map((p) => (
                      <div key={p.id} className={`p-4 rounded-[1.5rem] border bg-white shadow-xl animate-in zoom-in-95 duration-300 relative overflow-hidden group/card ${p.applied ? 'border-emerald-200' : 'border-indigo-100 ring-4 ring-indigo-50/50'}`}>
