        enum: ['Primary', 'Secondary'],
        description: "The category of the function."
      },
      function: { 
        type: Type.STRING,
        description: "The asset-level function description."
      },
      functionalFailure: { 
        type: Type.STRING,
        description: "The specific way the function is lost."
      },
      component: { 
        type: Type.STRING, 
        description: "The specific component." 
      },
      componentIntel: {
        type: Type.OBJECT,
        properties: {
          description: { 
            type: Type.STRING, 
            description: "A highly detailed 4-5 sentence technical engineering description of the component's role, material properties, and design philosophy." 
          },
          location: { 
            type: Type.STRING, 
            description: "A highly detailed 4-5 sentence description of where this is precisely found, its proximity to other sub-systems, and mounting details." 
          },
          visualCues: { 
            type: Type.STRING, 
            description: "A highly detailed 4-5 sentence guide on specific visual markers, tags, wear patterns, or colors to look for during a walkdown." 
          }
        },
        required: ["description", "location", "visualCues"]
      },
      failureMode: { 
        type: Type.STRING,
        description: "[Mechanism] due to [Cause]. Include technical wear AND specific human-induced errors (e.g., 'Improper torqueing by technician', 'Incorrect operational set-point')."
      },
      failureEffect: { 
        type: Type.STRING,
        description: "Operational and safety impact."
      },
      consequenceCategory: {
        type: Type.STRING,
        enum: [
          'Hidden - Safety/Env', 
          'Hidden - Operational', 
          'Evident - Safety/Env', 
          'Evident - Operational',
          'Evident - Non-Operational'
        ]
      },
      iso14224Code: { 
        type: Type.STRING,
        enum: ["BRD", "LOP", "ELP", "INL", "VIB", "OHE", "STP", "FTS", "FTC", "FTO", "UST", "NOI", "LCP", "OTH"],
        description: "Strict ISO 14224 Failure Mechanism Code."
      },
      criticality: { type: Type.STRING, enum: ["High", "Medium", "Low"] },
      severity: { type: Type.INTEGER },
      occurrence: { type: Type.INTEGER },
      detection: { type: Type.INTEGER },
      maintenanceTask: { 
        type: Type.STRING,
        description: "Exactly one technical maintenance task."
      },
      interval: { type: Type.STRING },
      taskType: {
        type: Type.STRING,
        enum: [
          'Condition Monitoring', 
          'Time-Based', 
          'Run-to-Failure', 
          'Redesign',
          'Failure Finding',
          'Lubrication',
          'Servicing',
          'Restoration',
          'Replacement',
          'Training',
          'Procedural Change'
        ]
      }
    },
    required: ["functionType", "component", "componentIntel", "function", "functionalFailure", "failureMode", "failureEffect", "consequenceCategory", "iso14224Code", "criticality", "severity", "occurrence", "detection", "maintenanceTask", "interval", "taskType"]
  }
};

