export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  language: string = 'English',
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    Analyze this asset as a WHOLE assembly.
    Operational Context: ${contextText}
    Target Language: ${language}

    STRICT TECHNICAL REQUIRMENTS:
    - CRITICAL: You must identify a balanced mix of mechanical/electrical failures AND failure modes caused by HUMAN MISTAKES (e.g., operator error, maintenance errors like over-lubrication, improper calibration, or installation errors).
    - EXHAUSTIVE ANALYSIS: Generate 60-80 failure modes.
    - ISO 14224 taxonomy mapping is mandatory.
    - Each failure mode must have exactly ONE task.
    - For each failure mode, describe the "failureEffect" clearly.
  `;

  const contents: any[] = [{ parts: [{ text: prompt }] }];
  if (fileData) {
    contents[0].parts.push({
      inlineData: { mimeType: fileData.mimeType, data: fileData.data }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents[0].parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: rcmSchema,
      temperature: 0.4,
      seed: 42
    }
  });

  const rawItems = JSON.parse(response.text || "[]");
  return rawItems.map((item: any) => ({
    ...item,
    id: `rcm-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
    rpn: (item.severity || 1) * (item.occurrence || 1) * (item.detection || 1),
    isNew: true
  }));
};

export const validateRCMAnalysis = async (items: RCMItem[], language: string = 'English'): Promise<{id: string, issues: string[]}[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const studyData = items.map(i => ({
    id: i.id,
    comp: i.component,
    cons: i.consequenceCategory,
    sev: i.severity,
    fm: i.failureMode,
    task: i.maintenanceTask,
    type: i.taskType
  }));

  const prompt = `
    Perform an RCM Logic Audit (SAE JA1011).
    Target Language: ${language}
    DATA: ${JSON.stringify(studyData)}

    AUDIT RULES:
    1. Check for missing HUMAN ERROR failure modes for high-criticality components (e.g., if a component is sensitive to installation error but none is listed).
    2. Hidden Failures MUST have Failure Finding tasks.
    3. Safety consequences cannot be Run-to-Failure.
    4. High RPN items must have robust task types.

    Return only items with logical gaps.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: validationSchema,
      temperature: 0.4,
      seed: 42
    }
  });

  return JSON.parse(response.text || "[]");
};

export const generateInspectionSheet = async (item: RCMItem, language: string = 'English'): Promise<InspectionSheet> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `Generate inspection protocol for: ${item.component}, Failure Mode: ${item.failureMode}, Task: ${item.maintenanceTask}. The protocol MUST be in ${language}.`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: inspectionSchema,
      temperature: 0.4,
      seed: 42
    }
  });
  return JSON.parse(response.text || "{}") as InspectionSheet;
};

export const generateComponentIntel = async (componentName: string, language: string = 'English'): Promise<ComponentIntel> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `Provide detailed physical and engineering identification for: ${componentName}. 
  You MUST provide at least 4-5 dense, technical sentences for each of the following sections to ensure maximum descriptive depth:
  1. description: A technical engineering description of the component, its role, and its material characteristics.
  2. location: Precise details on where this is located on the asset, what it is mounted near, and common access points.
  3. visualCues: How to identify it visually, including specific tags, color codes, or physical markers to look for during a maintenance walkdown.

  Language: ${language}`;

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: componentIntelSchema,
      temperature: 0.4,
      seed: 42
    }
  });
  return JSON.parse(response.text || "{}") as ComponentIntel;
};

export const extractOperationalContext = async (fileData: FileData, language: string = 'English'): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });
  const prompt = `Extract operational context summary in ${language}.`;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: {
      parts: [
        { text: prompt },
        { inlineData: { mimeType: fileData.mimeType, data: fileData.data } }
      ]
    },
    config: {
      temperature: 0.4,
      seed: 42
    }
  });
  return response.text || "";
};

