export const generateRCMAnalysis = async (
  contextText: string,
  fileData: FileData | null,
  language: string = 'English',
  existingItems: RCMItem[] = []
): Promise<RCMItem[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const prompt = `
    Analyze this asset as a WHOLE assembly.
    Operational Context: ${contextText}
    Target Language: ${language}

    CRITICAL QUALITY GUIDELINES:
    1. EXHAUSTIVE SCOPE: Generate a high volume of failure modes (60-80).
    2. HUMAN MISTAKES: You MUST identify failures caused by human mistakes (operator error, maintenance errors like over-tightening or wrong lubricant, installation mistakes).
    3. HIERARCHICAL PROCESS: Define functions, functional failures, specific components, and then failure modes.
    4. ISO 14224 CODES: Map every record to a strict 3-letter ISO code.
    5. COMPONENT INTEL: For EVERY component, provide 4-5 high-density technical sentences for description, location, and visual cues.
  `;

  const contents: any[] = [{ parts: [{ text: prompt }] }];
  if (fileData) {
    contents[0].parts.push({
      inlineData: { mimeType: fileData.mimeType, data: fileData.data }
    });
  }

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: { parts: contents[0].parts },
    config: {
      responseMimeType: "application/json",
      responseSchema: rcmSchema,
      temperature: 0.4,
      seed: 42
    }
  });

  const rawItems = JSON.parse(response.text || "[]");
  return rawItems.map((item: any) => ({
    ...item,
    id: `rcm-${Date.now()}-${Math.random().toString(36).substr(2, 5)}`,
    rpn: (item.severity || 1) * (item.occurrence || 1) * (item.detection || 1),
    isNew: true
  }));
};

export const validateRCMAnalysis = async (items: RCMItem[], language: string = 'English'): Promise<{id: string, issues: string[]}[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || "" });

  const studyData = items.map(i => ({
    id: i.id,
    comp: i.component,
    fm: i.failureMode,
    task: i.maintenanceTask,
    type: i.taskType
  }));

  const prompt = `
    Perform a Logic Audit based on SAE JA1011.
    Target Language: ${language}
    DATA: ${JSON.stringify(studyData)}

    AUDIT CHECKS:
    - Check for missing HUMAN ERROR modes on high-risk items.
    - Validate Hidden failure modes have Failure Finding tasks.
    - Flag Safety consequences with Run-to-Failure tasks.

    Return only items with logical violations.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: validationSchema,
      temperature: 0.4,
      seed: 42
    }
  });

  return JSON.parse(response.text || "[]");
};

