const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

const getScoreColor = (score: number) => {
  if (score >= 8) return 'text-red-600 font-bold';
  if (score >= 5) return 'text-amber-600 font-medium';
  return 'text-slate-500';
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, studyName, onUpdate, onUndo, canUndo, language }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);

  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet'; direction: 'asc' | 'desc' }>({ key: 'functionType', direction: 'asc' });
  const [searchFilters, setSearchFilters] = useState({
    component: '',
    functionType: '',
    function: '',
    failureMode: '',
    consequenceCategory: '',
    iso14224Code: ''
  });

  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [isValidating, setIsValidating] = useState(false);
  const [generatingIntelIds, setGeneratingIntelIds] = useState<Set<string>>(new Set());
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);
  const [optimizingItem, setOptimizingItem] = useState<RCMItem | null>(null);
  const [showCMMSBridge, setShowCMMSBridge] = useState(false);
  const [isExtracting, setIsExtracting] = useState(false);
  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => item !== null && item !== undefined);
    if (matrixFilter) result = result.filter(item => (item.severity || 0) === matrixFilter.s && (item.occurrence || 0) === matrixFilter.o);
    if (barFilter) result = result.filter(item => item.id === barFilter);
    if (searchFilters.component) result = result.filter(item => (item.component || '').toLowerCase().includes(searchFilters.component.toLowerCase()));
    if (searchFilters.functionType) result = result.filter(item => (item.functionType || '').toLowerCase() === searchFilters.functionType.toLowerCase());
    if (searchFilters.function) result = result.filter(item => (item.function || '').toLowerCase().includes(searchFilters.function.toLowerCase()));
    if (searchFilters.failureMode) result = result.filter(item => (item.failureMode || '').toLowerCase().includes(searchFilters.failureMode.toLowerCase()));
    if (searchFilters.consequenceCategory) result = result.filter(item => (item.consequenceCategory || '').toLowerCase().includes(searchFilters.consequenceCategory.toLowerCase()));
    if (searchFilters.iso14224Code) result = result.filter(item => (item.iso14224Code || '').toLowerCase().includes(searchFilters.iso14224Code.toLowerCase()));

    result.sort((a, b) => {
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;
      const secondarySort = (x: RCMItem, y: RCMItem) => {
        const ft = (x.functionType || '').localeCompare(y.functionType || '');
        if (ft !== 0) return ft;
        const f = (x.function || '').localeCompare(y.function || '');
        if (f !== 0) return f;
        const ff = (x.functionalFailure || '').localeCompare(y.functionalFailure || '');
        if (ff !== 0) return ff;
        const comp = (x.component || '').localeCompare(y.component || '');
        if (comp !== 0) return comp;
        return (x.failureMode || '').localeCompare(y.failureMode || '');
      };
      if (sortConfig.key === 'status_color') {
        const aVal = (a.isNew ? 1 : 0) * 1000 + (a.rpn || 0);
        const bVal = (b.isNew ? 1 : 0) * 1000 + (b.rpn || 0);
        if (aVal === bVal) return secondarySort(a, b);
        return (bVal - aVal) * multiplier;
      }
      if (sortConfig.key === 'inspectionSheet') {
        const aHas = a.inspectionSheet ? 1 : 0;
        const bHas = b.inspectionSheet ? 1 : 0;
        if (aHas === bHas) return secondarySort(a, b);
        return (aHas - bHas) * multiplier;
      }
      const aVal = a[sortConfig.key as keyof RCMItem];
      const bVal = b[sortConfig.key as keyof RCMItem];
      if (aVal === bVal) return secondarySort(a, b);
      if (aVal === undefined || aVal === null) return 1;
      if (bVal === undefined || bVal === null) return -1;
      if (typeof aVal === 'string' && typeof bVal === 'string') return aVal.localeCompare(bVal) * multiplier;
      return ((aVal as number) - (bVal as number)) * multiplier;
    });
    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  const handleInternalUndo = () => {
    onUndo();
    setTimeout(() => {
       if (viewSheet) {
          const updatedItem = data.find(i => i.id === viewSheet.item.id);
          if (updatedItem) setViewSheet({ item: updatedItem });
       }
       if (selectedIntel) {
          const updatedItem = data.find(i => i.id === selectedIntel.id);
          if (updatedItem) setSelectedIntel(updatedItem);
       }
    }, 0);
  };

  const requestSort = (key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') direction = 'desc';
    else if (key === 'rpn' || key === 'status_color' || key === 'inspectionSheet') direction = 'desc';
    setSortConfig({ key, direction });
  };

  const handleSearchChange = (field: keyof typeof searchFilters, value: string) => setSearchFilters(prev => ({ ...prev, [field]: value }));
  const handleDelete = (id: string) => {
    const newData = data.filter(item => item.id !== id);
    onUpdate(newData);
    if (viewSheet?.item.id === id) setViewSheet(null);
  };
  const handleEdit = (item: RCMItem) => {
    setEditingId(item.id);
    setEditForm({ ...item });
  };
  const handleCancel = () => {
    setEditingId(null);
    setEditForm(null);
  };
  const handleSave = async () => {
    if (!editForm || !editingId) return;
    const originalItem = data.find(d => d.id === editingId);
    if (!originalItem) return;
    const hasCriticalChanges = editForm.maintenanceTask !== originalItem.maintenanceTask || editForm.failureMode !== originalItem.failureMode || editForm.component !== originalItem.component;
    const needsRegeneration = hasCriticalChanges && !!originalItem.inspectionSheet;
    const updatedForm = { ...editForm, rpn: (editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1), inspectionSheet: needsRegeneration ? undefined : editForm.inspectionSheet, isNew: false };
    const newData = data.map(item => item.id === editingId ? updatedForm : item);
    onUpdate(newData);
    setEditingId(null);
    setEditForm(null);
    if (needsRegeneration) {
      setRegeneratingIds(prev => new Set(prev).add(updatedForm.id));
      try {
        const newSheet = await generateInspectionSheet(updatedForm, language);
        const finalData = newData.map(item => item.id === updatedForm.id ? { ...item, inspectionSheet: newSheet } : item);
        onUpdate(finalData);
      } catch (err) { console.error(err); } finally {
        setRegeneratingIds(prev => { const next = new Set(prev); next.delete(updatedForm.id); return next; });
      }
    }
  };

  const handleChange = (field: keyof RCMItem, value: any) => {
    if (!editForm) return;
    setEditForm({ ...editForm, [field]: value });
  };

  const handleIntelClick = async (item: RCMItem) => {
    if (item.componentIntel && item.componentIntel.description) {
      setSelectedIntel(item);
      return;
    }
    setGeneratingIntelIds(prev => new Set(prev).add(item.id));
    try {
      const intel = await generateComponentIntel(item.component, language);
      const newItem = { ...item, componentIntel: intel };
      const newData = data.map(d => d.id === item.id ? newItem : d);
      onUpdate(newData);
      setSelectedIntel(newItem);
    } catch (e) {
      alert("Failed to synthesize component intelligence.");
    } finally {
      setGeneratingIntelIds(prev => { const next = new Set(prev); next.delete(item.id); return next; });
    }
  };

  const handleGenerateSingleSheet = async (item: RCMItem) => {
    setRegeneratingIds(prev => new Set(prev).add(item.id));
    try {
      const sheet = await generateInspectionSheet(item, language);
      const newData = data.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d);
      onUpdate(newData);
      const updatedItem = newData.find(d => d.id === item.id);
      if (updatedItem) setViewSheet({ item: updatedItem });
    } catch (e) { alert("Failed to generate."); } finally {
      setRegeneratingIds(prev => { const next = new Set(prev); next.delete(item.id); return next; });
    }
  };

  const handleGenerateAllSheets = async () => {
    const itemsToProcess = data.filter(item => !item.inspectionSheet);
    if (itemsToProcess.length === 0) return;
    setGeneratingSheets(true);
    setProgress({ current: 0, total: itemsToProcess.length });
    let currentData = [...data];
    const BATCH_SIZE = 3;
    for (let i = 0; i < itemsToProcess.length; i += BATCH_SIZE) {
      const batch = itemsToProcess.slice(i, i + BATCH_SIZE);
      await Promise.all(batch.map(async (item) => {
        try {
          const sheet = await generateInspectionSheet(item, language);
          const index = currentData.findIndex(d => d.id === item.id);
          if (index !== -1) currentData[index] = { ...currentData[index], inspectionSheet: sheet };
        } catch (e) {}
      }));
      setProgress(prev => ({ ...prev, current: Math.min(prev.total, i + BATCH_SIZE) }));
      onUpdate([...currentData]);
    }
    setGeneratingSheets(false);
  };

  const handleValidateLogic = async () => {
    if (data.length === 0) return;
    setIsValidating(true);
    try {
      const issues = await validateRCMAnalysis(data, language);
      const newData = data.map(item => {
        const match = issues.find(issue => issue.id === item.id);
        return { ...item, validationIssues: match ? match.issues : [] };
      });
      onUpdate(newData);
    } catch (e) { alert("Logic validation failed."); } finally { setIsValidating(false); }
  };

  const renderComponentIntelModal = () => {
    if (!selectedIntel) return null;
    const intel = selectedIntel.componentIntel;

    return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
        <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-5xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-300 border border-slate-100 max-h-[90vh]">
          {/* Header */}
          <div className="bg-slate-900 px-8 py-6 flex justify-between items-center text-white shrink-0 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none">
              <Box size={120} className="rotate-12" />
            </div>
            <div className="flex items-center gap-5 relative z-10">
              <div className="p-3.5 bg-indigo-500/20 rounded-[1.2rem] border border-indigo-500/30">
                <Cog size={28} className="text-indigo-400" />
              </div>
              <div>
                <h3 className="font-black text-xl tracking-tighter uppercase leading-none">Asset Architecture Breakdown</h3>
                <p className="text-[10px] text-indigo-400 font-black uppercase tracking-[0.2em] mt-2">{selectedIntel.component}</p>
              </div>
            </div>
            <div className="flex items-center gap-3 relative z-10">
              <button
                onClick={handleInternalUndo}
                disabled={!canUndo}
                className={`p-2.5 rounded-full transition-all ${canUndo ? 'bg-white/10 text-white hover:bg-white/20' : 'text-slate-600 opacity-20'}`}
              >
                <Undo2 size={22} />
              </button>
              <button onClick={() => setSelectedIntel(null)} className="p-2.5 bg-white/5 text-slate-400 hover:bg-white/10 hover:text-white rounded-full transition-all">
                <X size={26} />
              </button>
            </div>
          </div>

          <div className="p-10 space-y-8 bg-slate-50/50 overflow-y-auto custom-scrollbar flex-1">
            {/* 3 High-Density Boxes Grid */}
            <div className="grid grid-cols-1 gap-8">
              {/* Box 1: Engineering Description */}
              <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-2 h-full bg-indigo-600/10 group-hover:bg-indigo-600 transition-colors"></div>
                <div className="flex items-center gap-3 mb-5">
                  <FileText size={20} className="text-indigo-600" />
                  <h4 className="text-[11px] font-black uppercase tracking-[0.25em] text-slate-400">Functional Engineering Summary</h4>
                </div>
                <p className="text-[15px] text-slate-800 leading-relaxed font-bold tracking-tight italic">
                  {intel?.description || "Technical description unavailable."}
                </p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Box 2: Mounting & Location */}
                <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm">
                  <div className="flex items-center gap-3 mb-5 text-amber-600">
                    <MapPin size={20} />
                    <h4 className="text-[11px] font-black uppercase tracking-[0.25em]">Placement & Mounting Logic</h4>
                  </div>
                  <p className="text-[13px] text-slate-700 font-bold leading-relaxed whitespace-pre-wrap">
                    {intel?.location || "Location data unavailable."}
                  </p>
                </div>

                {/* Box 3: Visual Identification */}
                <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm">
                  <div className="flex items-center gap-3 mb-5 text-emerald-600">
                    <Eye size={20} />
                    <h4 className="text-[11px] font-black uppercase tracking-[0.25em]">Visual Walkdown Cues</h4>
                  </div>
                  <p className="text-[13px] text-slate-700 font-bold leading-relaxed whitespace-pre-wrap">
                    {intel?.visualCues || "Visual cues unavailable."}
                  </p>
                </div>
              </div>
            </div>
          </div>

          <div className="px-10 py-8 bg-white border-t border-slate-100 flex justify-between items-center shrink-0">
             <div className="flex items-center gap-3">
               <div className="w-2.5 h-2.5 rounded-full bg-indigo-600 animate-pulse"></div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Engineering Technical Specification v3.0</span>
             </div>
             <button 
               onClick={() => setSelectedIntel(null)}
               className="px-14 py-4 bg-slate-900 text-white rounded-[1.2rem] text-[10px] font-black uppercase tracking-[0.2em] hover:bg-indigo-600 transition-all active:scale-95 shadow-2xl shadow-slate-200"
             >
               Confirm Architecture Review
             </button>
          </div>
        </div>
      </div>
    );
  };

  const isFiltered = !!matrixFilter || !!barFilter || !!searchFilters.component || !!searchFilters.functionType || !!searchFilters.function || !!searchFilters.failureMode || !!searchFilters.consequenceCategory || !!searchFilters.iso14224Code;
  const topRisks = data.sort((a, b) => (b.rpn || 0) - (a.rpn || 0)).slice(0, 5).map(item => ({ id: item.id, name: item.component, rpn: item.rpn || 0 }));
  const stats = [
    { label: 'Total Failures', value: data.length, icon: ListChecks, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Max RPN', value: Math.max(...data.map(i => i.rpn || 0), 0), icon: AlertOctagon, color: 'text-red-600', bg: 'bg-red-50' },
    { label: 'Condition Monitoring', value: data.filter(i => i.taskType === 'Condition Monitoring').length, icon: Zap, color: 'text-indigo-600', bg: 'bg-indigo-50' },
    { label: 'Human factor fixes', value: data.filter(i => i.taskType === 'Training' || i.taskType === 'Procedural Change').length, icon: UserPlus, color: 'text-purple-600', bg: 'bg-purple-50' },
  ];

  const renderSortIcon = (key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet') => {
    if (sortConfig.key !== key) return <ArrowUpDown size={14} className="text-slate-300" />;
    return sortConfig.direction === 'asc' ? <ArrowUp size={14} className="text-indigo-600" /> : <ArrowDown size={14} className="text-indigo-600" />;
  };

  return (
    <div className="space-y-8 animate-fade-in relative w-full">
      {renderComponentIntelModal()}
      <CMMSBridgeModal data={data} isOpen={showCMMSBridge} onClose={() => setShowCMMSBridge(false)} />

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {stats.map((stat, i) => (
           <div key={i} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-xl ${stat.bg} ${stat.color} flex items-center justify-center shrink-0`}>
                <stat.icon size={24} />
              </div>
              <div>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-none mb-2">{stat.label}</p>
                <h3 className="text-2xl font-bold text-slate-800 leading-none">{stat.value}</h3>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
        <div className="xl:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col">
          <div className="flex justify-between items-start mb-6">
            <div><h3 className="text-lg font-bold text-slate-800 flex items-center gap-2"><AlertTriangle size={20} className="text-orange-500" />Criticality Matrix</h3></div>
          </div>
          <div className="flex-1 min-h-[300px] flex items-center justify-center relative">
             <div className="relative w-full max-w-sm aspect-square">
                <div className="grid grid-cols-10 grid-rows-10 gap-0.5 w-full h-full">
                   {Array.from({ length: 100 }).map((_, idx) => {
                      const x = (idx % 10) + 1; const y = 10 - Math.floor(idx / 10); const score = x * y;
                      let bgClass = score >= 50 ? "bg-red-50 border-red-100" : score >= 20 ? "bg-amber-50 border-amber-100" : "bg-emerald-50 border-emerald-100";
                      const isSelected = matrixFilter?.s === x && matrixFilter?.o === y;
                      if (isSelected) bgClass = "bg-indigo-600 border-indigo-700 ring-2 ring-indigo-300 z-10";
                      const count = data.filter(d => (d.severity || 0) === x && (d.occurrence || 0) === y).length;
                      return (<button key={idx} onClick={() => handleMatrixClick(x, y)} className={`border rounded-sm relative transition-all hover:scale-110 flex items-center justify-center ${bgClass}`}>{count > 0 && <span className={`text-[10px] font-black ${isSelected ? 'text-white' : 'text-slate-500'}`}>{count}</span>}</button>);
                   })}
                </div>
             </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Risk Profile</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={topRisks} layout="vertical">
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 11}} />
                <Bar dataKey="rpn" fill="#4f46e5" radius={[0, 4, 4, 0]} onClick={(d) => handleBarClick(d.id)} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b flex flex-wrap justify-between items-center gap-4 bg-slate-50/50">
          <div className="flex items-center gap-3"><FileText size={20} className="text-indigo-600" /><div><h3 className="text-lg font-bold">FMECA Analysis</h3><p className="text-xs text-slate-500">Industry Standard SAE JA1011</p></div></div>
          <div className="flex gap-2">
            <button onClick={handleValidateLogic} disabled={isValidating} className="flex items-center gap-2 px-4 py-2 bg-white border rounded-xl text-xs font-bold hover:bg-slate-50 transition-all">{isValidating ? <Loader2 size={16} className="animate-spin" /> : <ShieldCheck size={16} />} Validate Audit</button>
            <button onClick={() => setShowCMMSBridge(true)} className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-indigo-600 transition-all"><Layers size={16} /> CMMS Sync</button>
          </div>
        </div>

        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/80 border-b border-slate-200 text-[10px] font-black uppercase tracking-widest text-slate-400">
                <th className="px-6 py-4">Type</th>
                <th className="px-6 py-4">Function / Component</th>
                <th className="px-6 py-4">Failure Mode</th>
                <th className="px-6 py-4 w-12 text-center">S</th>
                <th className="px-6 py-4 w-12 text-center">O</th>
                <th className="px-6 py-4 w-12 text-center">D</th>
                <th className="px-6 py-4 w-16">RPN</th>
                <th className="px-6 py-4">Strategy</th>
                <th className="px-6 py-4 w-16"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm">
              {processedData.map((item) => {
                const hasIssues = item.validationIssues && item.validationIssues.length > 0;
                const isHumanFactor = item.taskType === 'Training' || item.taskType === 'Procedural Change';

                return (
                  <tr key={item.id} className={`group hover:bg-slate-50/50 ${hasIssues ? 'bg-red-50/10 border-l-4 border-l-red-500' : ''} ${item.isNew ? 'bg-emerald-50/30' : ''}`}>
                    <td className="px-6 py-5 align-top"><span className={`text-[9px] font-black px-2 py-1 rounded border ${item.functionType === 'Primary' ? 'bg-slate-900 text-white border-slate-900' : 'bg-slate-100 text-slate-500 border-slate-200'}`}>{item.functionType}</span></td>
                    <td className="px-6 py-5 align-top">
                      <p className="text-[11px] font-bold text-slate-900 uppercase tracking-tight">{item.function}</p>
                      <div className="flex items-center gap-2 mt-1">
                        <span className="text-[10px] text-slate-500 font-bold uppercase">{item.component}</span>
                        <button onClick={() => handleIntelClick(item)} className="p-1 text-slate-300 hover:text-indigo-600"><Info size={14} /></button>
                      </div>
                    </td>
                    <td className="px-6 py-5 align-top">
                      <p className="text-[11px] font-bold text-slate-700 leading-tight uppercase">{item.failureMode}</p>
                      {hasIssues && <div className="flex items-center gap-1 text-red-500 text-[9px] font-black uppercase mt-1"><ShieldX size={12} /> Logic Risk</div>}
                    </td>
                    <td className="px-6 py-5 align-middle text-center"><span className={getScoreColor(item.severity)}>{item.severity}</span></td>
                    <td className="px-6 py-5 align-middle text-center"><span className={getScoreColor(item.occurrence)}>{item.occurrence}</span></td>
                    <td className="px-6 py-5 align-middle text-center"><span className={getScoreColor(item.detection)}>{item.detection}</span></td>
                    <td className="px-6 py-5 align-middle"><span className="text-xs font-bold text-slate-800">{item.rpn}</span></td>
                    <td className="px-6 py-5 align-top">
                      <p className="text-[11px] font-bold text-indigo-700 leading-tight uppercase">{item.maintenanceTask}</p>
                      <div className="flex items-center gap-2 mt-1">
                        <span className="text-[9px] text-slate-400 font-black uppercase">{item.interval}</span>
                        {isHumanFactor && <span className="text-[8px] bg-purple-50 text-purple-600 px-1.5 py-0.5 rounded border border-purple-100 font-black uppercase">Human Factor Fix</span>}
                      </div>
                    </td>
                    <td className="px-6 py-5 align-middle text-right opacity-0 group-hover:opacity-100 transition-opacity">
                      <div className="flex justify-end gap-1">
                        <button onClick={() => handleEdit(item)} className="p-1.5 text-slate-400 hover:text-indigo-600"><Pencil size={16} /></button>
                        <button onClick={() => handleDelete(item.id)} className="p-1.5 text-slate-400 hover:text-red-600"><Trash2 size={16} /></button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { RCMItem, InspectionSheet, InspectionStep, ConsequenceCategory, ComponentIntel } from '../types';
import { generateInspectionSheet, generateComponentIntel, validateRCMAnalysis } from '../services/geminiService';
import { IntervalOptimizerModal } from './IntervalOptimizerModal';
import { CMMSBridgeModal } from './CMMSBridgeModal';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, ResponsiveContainer, Tooltip as RechartsTooltip, Cell 
} from 'recharts';
import { 
  AlertTriangle, CheckCircle, Clock, Activity, FileText, 
  Pencil, Trash2, Save, X, ClipboardList, Loader2,
  FileCheck, File, AlertOctagon, FilterX, User, ShieldAlert, Wrench, Search, ChevronRight, RefreshCw,
  ArrowUpDown, ArrowUp, ArrowDown, Filter, Plus, Tag, ShieldCheck, Zap, ListChecks, Info, MapPin, Eye, Undo2, Target, Palette, Box, Layers, UserPlus, Download, ShieldX, Cog
} from 'lucide-react';

interface AnalysisResultProps {
  data: RCMItem[];
  studyName: string;
  onUpdate: (newData: RCMItem[]) => void;
  onUndo: () => void;
  canUndo: boolean;
  language: string;
}

const CONSEQUENCE_LABELS: ConsequenceCategory[] = [
  'Hidden - Safety/Env', 
  'Hidden - Operational', 
  'Evident - Safety/Env', 
  'Evident - Operational',
  'Evident - Non-Operational'
];

const getRPNColorStyle = (rpn: number) => {
  if (rpn >= 120) return { bg: 'bg-red-100', text: 'text-red-900', bar: 'bg-red-500' };
  if (rpn >= 75) return { bg: 'bg-orange-100', text: 'text-orange-900', bar: 'bg-orange-500' };
  if (rpn >= 40) return { bg: 'bg-yellow-50', text: 'text-yellow-800', bar: 'bg-yellow-400' };
  return { bg: 'bg-emerald-50', text: 'text-emerald-800', bar: 'bg-emerald-400' };
};

const getScoreColor = (score: number) => {
  if (score >= 8) return 'text-red-600 font-bold';
  if (score >= 5) return 'text-amber-600 font-medium';
  return 'text-slate-500';
};

export const AnalysisResult: React.FC<AnalysisResultProps> = ({ data, studyName, onUpdate, onUndo, canUndo, language }) => {
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<RCMItem | null>(null);
  const [matrixFilter, setMatrixFilter] = useState<{s: number, o: number} | null>(null);
  const [barFilter, setBarFilter] = useState<string | null>(null);
  const [selectedIntel, setSelectedIntel] = useState<RCMItem | null>(null);

  const [sortConfig, setSortConfig] = useState<{ key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet'; direction: 'asc' | 'desc' }>({ key: 'functionType', direction: 'asc' });
  const [searchFilters, setSearchFilters] = useState({
    component: '',
    functionType: '',
    function: '',
    failureMode: '',
    consequenceCategory: '',
    iso14224Code: ''
  });

  const [generatingSheets, setGeneratingSheets] = useState(false);
  const [isValidating, setIsValidating] = useState(false);
  const [generatingIntelIds, setGeneratingIntelIds] = useState<Set<string>>(new Set());
  const [progress, setProgress] = useState({ current: 0, total: 0 });
  const [viewSheet, setViewSheet] = useState<{item: RCMItem} | null>(null);
  const [editingStepIdx, setEditingStepIdx] = useState<number | null>(null);
  const [optimizingItem, setOptimizingItem] = useState<RCMItem | null>(null);
  const [showCMMSBridge, setShowCMMSBridge] = useState(false);
  const [isExtracting, setIsExtracting] = useState(false);
  const [regeneratingIds, setRegeneratingIds] = useState<Set<string>>(new Set());

  const processedData = useMemo(() => {
    let result = (data || []).filter(item => item !== null && item !== undefined);
    if (matrixFilter) result = result.filter(item => (item.severity || 0) === matrixFilter.s && (item.occurrence || 0) === matrixFilter.o);
    if (barFilter) result = result.filter(item => item.id === barFilter);
    if (searchFilters.component) result = result.filter(item => (item.component || '').toLowerCase().includes(searchFilters.component.toLowerCase()));
    if (searchFilters.functionType) result = result.filter(item => (item.functionType || '').toLowerCase() === searchFilters.functionType.toLowerCase());
    if (searchFilters.function) result = result.filter(item => (item.function || '').toLowerCase().includes(searchFilters.function.toLowerCase()));
    if (searchFilters.failureMode) result = result.filter(item => (item.failureMode || '').toLowerCase().includes(searchFilters.failureMode.toLowerCase()));
    if (searchFilters.consequenceCategory) result = result.filter(item => (item.consequenceCategory || '').toLowerCase().includes(searchFilters.consequenceCategory.toLowerCase()));
    if (searchFilters.iso14224Code) result = result.filter(item => (item.iso14224Code || '').toLowerCase().includes(searchFilters.iso14224Code.toLowerCase()));

    result.sort((a, b) => {
      const multiplier = sortConfig.direction === 'asc' ? 1 : -1;
      const secondarySort = (x: RCMItem, y: RCMItem) => {
        const ft = (x.functionType || '').localeCompare(y.functionType || '');
        if (ft !== 0) return ft;
        const f = (x.function || '').localeCompare(y.function || '');
        if (f !== 0) return f;
        const ff = (x.functionalFailure || '').localeCompare(y.functionalFailure || '');
        if (ff !== 0) return ff;
        const comp = (x.component || '').localeCompare(y.component || '');
        if (comp !== 0) return comp;
        return (x.failureMode || '').localeCompare(y.failureMode || '');
      };
      if (sortConfig.key === 'status_color') {
        const aVal = (a.isNew ? 1 : 0) * 1000 + (a.rpn || 0);
        const bVal = (b.isNew ? 1 : 0) * 1000 + (b.rpn || 0);
        if (aVal === bVal) return secondarySort(a, b);
        return (bVal - aVal) * multiplier;
      }
      if (sortConfig.key === 'inspectionSheet') {
        const aHas = a.inspectionSheet ? 1 : 0;
        const bHas = b.inspectionSheet ? 1 : 0;
        if (aHas === bHas) return secondarySort(a, b);
        return (aHas - bHas) * multiplier;
      }
      const aVal = a[sortConfig.key as keyof RCMItem];
      const bVal = b[sortConfig.key as keyof RCMItem];
      if (aVal === bVal) return secondarySort(a, b);
      if (aVal === undefined || aVal === null) return 1;
      if (bVal === undefined || bVal === null) return -1;
      if (typeof aVal === 'string' && typeof bVal === 'string') return aVal.localeCompare(bVal) * multiplier;
      return ((aVal as number) - (bVal as number)) * multiplier;
    });
    return result;
  }, [data, matrixFilter, barFilter, sortConfig, searchFilters]);

  const handleInternalUndo = () => {
    onUndo();
    setTimeout(() => {
       if (viewSheet) {
          const updatedItem = data.find(i => i.id === viewSheet.item.id);
          if (updatedItem) setViewSheet({ item: updatedItem });
       }
       if (selectedIntel) {
          const updatedItem = data.find(i => i.id === selectedIntel.id);
          if (updatedItem) setSelectedIntel(updatedItem);
       }
    }, 0);
  };

  const requestSort = (key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet') => {
    let direction: 'asc' | 'desc' = 'asc';
    if (sortConfig.key === key && sortConfig.direction === 'asc') direction = 'desc';
    else if (key === 'rpn' || key === 'status_color' || key === 'inspectionSheet') direction = 'desc';
    setSortConfig({ key, direction });
  };

  const handleSearchChange = (field: keyof typeof searchFilters, value: string) => setSearchFilters(prev => ({ ...prev, [field]: value }));

  // Add missing handleMatrixClick function to toggle the matrix filter based on Severity (s) and Occurrence (o)
  const handleMatrixClick = (s: number, o: number) => {
    setMatrixFilter(prev => (prev?.s === s && prev?.o === o ? null : { s, o }));
    setBarFilter(null);
  };

  // Add missing handleBarClick function to toggle filtering for a specific component ID from the risk profile bar chart
  const handleBarClick = (id: string) => {
    setBarFilter(prev => (prev === id ? null : id));
    setMatrixFilter(null);
  };

  const handleDelete = (id: string) => {
    const newData = data.filter(item => item.id !== id);
    onUpdate(newData);
    if (viewSheet?.item.id === id) setViewSheet(null);
  };
  const handleEdit = (item: RCMItem) => {
    setEditingId(item.id);
    setEditForm({ ...item });
  };
  const handleCancel = () => {
    setEditingId(null);
    setEditForm(null);
  };
  const handleSave = async () => {
    if (!editForm || !editingId) return;
    const originalItem = data.find(d => d.id === editingId);
    if (!originalItem) return;
    const hasCriticalChanges = editForm.maintenanceTask !== originalItem.maintenanceTask || editForm.failureMode !== originalItem.failureMode || editForm.component !== originalItem.component;
    const needsRegeneration = hasCriticalChanges && !!originalItem.inspectionSheet;
    const updatedForm = { ...editForm, rpn: (editForm.severity || 1) * (editForm.occurrence || 1) * (editForm.detection || 1), inspectionSheet: needsRegeneration ? undefined : editForm.inspectionSheet, isNew: false };
    const newData = data.map(item => item.id === editingId ? updatedForm : item);
    onUpdate(newData);
    setEditingId(null);
    setEditForm(null);
    if (needsRegeneration) {
      setRegeneratingIds(prev => new Set(prev).add(updatedForm.id));
      try {
        const newSheet = await generateInspectionSheet(updatedForm, language);
        const finalData = newData.map(item => item.id === updatedForm.id ? { ...item, inspectionSheet: newSheet } : item);
        onUpdate(finalData);
      } catch (err) { console.error(err); } finally {
        setRegeneratingIds(prev => { const next = new Set(prev); next.delete(updatedForm.id); return next; });
      }
    }
  };

  const handleChange = (field: keyof RCMItem, value: any) => {
    if (!editForm) return;
    setEditForm({ ...editForm, [field]: value });
  };

  const handleIntelClick = async (item: RCMItem) => {
    if (item.componentIntel && item.componentIntel.description) {
      setSelectedIntel(item);
      return;
    }
    setGeneratingIntelIds(prev => new Set(prev).add(item.id));
    try {
      const intel = await generateComponentIntel(item.component, language);
      const newItem = { ...item, componentIntel: intel };
      const newData = data.map(d => d.id === item.id ? newItem : d);
      onUpdate(newData);
      setSelectedIntel(newItem);
    } catch (e) {
      alert("Failed to synthesize component intelligence.");
    } finally {
      setGeneratingIntelIds(prev => { const next = new Set(prev); next.delete(item.id); return next; });
    }
  };

  const handleGenerateSingleSheet = async (item: RCMItem) => {
    setRegeneratingIds(prev => new Set(prev).add(item.id));
    try {
      const sheet = await generateInspectionSheet(item, language);
      const newData = data.map(d => d.id === item.id ? { ...d, inspectionSheet: sheet } : d);
      onUpdate(newData);
      const updatedItem = newData.find(d => d.id === item.id);
      if (updatedItem) setViewSheet({ item: updatedItem });
    } catch (e) { alert("Failed to generate."); } finally {
      setRegeneratingIds(prev => { const next = new Set(prev); next.delete(item.id); return next; });
    }
  };

  const handleGenerateAllSheets = async () => {
    const itemsToProcess = data.filter(item => !item.inspectionSheet);
    if (itemsToProcess.length === 0) return;
    setGeneratingSheets(true);
    setProgress({ current: 0, total: itemsToProcess.length });
    let currentData = [...data];
    const BATCH_SIZE = 3;
    for (let i = 0; i < itemsToProcess.length; i += BATCH_SIZE) {
      const batch = itemsToProcess.slice(i, i + BATCH_SIZE);
      await Promise.all(batch.map(async (item) => {
        try {
          const sheet = await generateInspectionSheet(item, language);
          const index = currentData.findIndex(d => d.id === item.id);
          if (index !== -1) currentData[index] = { ...currentData[index], inspectionSheet: sheet };
        } catch (e) {}
      }));
      setProgress(prev => ({ ...prev, current: Math.min(prev.total, i + BATCH_SIZE) }));
      onUpdate([...currentData]);
    }
    setGeneratingSheets(false);
  };

  const handleValidateLogic = async () => {
    if (data.length === 0) return;
    setIsValidating(true);
    try {
      const issues = await validateRCMAnalysis(data, language);
      const newData = data.map(item => {
        const match = issues.find(issue => issue.id === item.id);
        return { ...item, validationIssues: match ? match.issues : [] };
      });
      onUpdate(newData);
    } catch (e) { alert("Logic validation failed."); } finally { setIsValidating(false); }
  };

  const renderComponentIntelModal = () => {
    if (!selectedIntel) return null;
    const intel = selectedIntel.componentIntel;

    return (
      <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4 animate-in fade-in duration-200">
        <div className="bg-white rounded-[2.5rem] shadow-2xl w-full max-w-5xl overflow-hidden flex flex-col animate-in zoom-in-95 duration-300 border border-slate-100 max-h-[90vh]">
          {/* Header */}
          <div className="bg-slate-900 px-8 py-6 flex justify-between items-center text-white shrink-0 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-10 pointer-events-none">
              <Box size={120} className="rotate-12" />
            </div>
            <div className="flex items-center gap-5 relative z-10">
              <div className="p-3.5 bg-indigo-500/20 rounded-[1.2rem] border border-indigo-500/30">
                <Cog size={28} className="text-indigo-400" />
              </div>
              <div>
                <h3 className="font-black text-xl tracking-tighter uppercase leading-none">Asset Architecture Breakdown</h3>
                <p className="text-[10px] text-indigo-400 font-black uppercase tracking-[0.2em] mt-2">{selectedIntel.component}</p>
              </div>
            </div>
            <div className="flex items-center gap-3 relative z-10">
              <button
                onClick={handleInternalUndo}
                disabled={!canUndo}
                className={`p-2.5 rounded-full transition-all ${canUndo ? 'bg-white/10 text-white hover:bg-white/20' : 'text-slate-600 opacity-20'}`}
              >
                <Undo2 size={22} />
              </button>
              <button onClick={() => setSelectedIntel(null)} className="p-2.5 bg-white/5 text-slate-400 hover:bg-white/10 hover:text-white rounded-full transition-all">
                <X size={26} />
              </button>
            </div>
          </div>

          <div className="p-10 space-y-8 bg-slate-50/50 overflow-y-auto custom-scrollbar flex-1">
            {/* 3 High-Density Boxes Grid */}
            <div className="grid grid-cols-1 gap-8">
              {/* Box 1: Engineering Description */}
              <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm relative overflow-hidden group">
                <div className="absolute top-0 left-0 w-2 h-full bg-indigo-600/10 group-hover:bg-indigo-600 transition-colors"></div>
                <div className="flex items-center gap-3 mb-5">
                  <FileText size={20} className="text-indigo-600" />
                  <h4 className="text-[11px] font-black uppercase tracking-[0.25em] text-slate-400">Functional Engineering Summary</h4>
                </div>
                <p className="text-[15px] text-slate-800 leading-relaxed font-bold tracking-tight italic">
                  {intel?.description || "Technical description unavailable."}
                </p>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* Box 2: Mounting & Location */}
                <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm">
                  <div className="flex items-center gap-3 mb-5 text-amber-600">
                    <MapPin size={20} />
                    <h4 className="text-[11px] font-black uppercase tracking-[0.25em]">Placement & Mounting Logic</h4>
                  </div>
                  <p className="text-[13px] text-slate-700 font-bold leading-relaxed whitespace-pre-wrap">
                    {intel?.location || "Location data unavailable."}
                  </p>
                </div>

                {/* Box 3: Visual Identification */}
                <div className="bg-white p-8 rounded-[2rem] border border-slate-200 shadow-sm">
                  <div className="flex items-center gap-3 mb-5 text-emerald-600">
                    <Eye size={20} />
                    <h4 className="text-[11px] font-black uppercase tracking-[0.25em]">Visual Walkdown Cues</h4>
                  </div>
                  <p className="text-[13px] text-slate-700 font-bold leading-relaxed whitespace-pre-wrap">
                    {intel?.visualCues || "Visual cues unavailable."}
                  </p>
                </div>
              </div>
            </div>
          </div>

          <div className="px-10 py-8 bg-white border-t border-slate-100 flex justify-between items-center shrink-0">
             <div className="flex items-center gap-3">
               <div className="w-2.5 h-2.5 rounded-full bg-indigo-600 animate-pulse"></div>
               <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Engineering Technical Specification v3.0</span>
             </div>
             <button 
               onClick={() => setSelectedIntel(null)}
               className="px-14 py-4 bg-slate-900 text-white rounded-[1.2rem] text-[10px] font-black uppercase tracking-[0.2em] hover:bg-indigo-600 transition-all active:scale-95 shadow-2xl shadow-slate-200"
             >
               Confirm Architecture Review
             </button>
          </div>
        </div>
      </div>
    );
  };

  const isFiltered = !!matrixFilter || !!barFilter || !!searchFilters.component || !!searchFilters.functionType || !!searchFilters.function || !!searchFilters.failureMode || !!searchFilters.consequenceCategory || !!searchFilters.iso14224Code;
  const topRisks = data.sort((a, b) => (b.rpn || 0) - (a.rpn || 0)).slice(0, 5).map(item => ({ id: item.id, name: item.component, rpn: item.rpn || 0 }));
  const stats = [
    { label: 'Total Failures', value: data.length, icon: ListChecks, color: 'text-blue-600', bg: 'bg-blue-50' },
    { label: 'Max RPN', value: Math.max(...data.map(i => i.rpn || 0), 0), icon: AlertOctagon, color: 'text-red-600', bg: 'bg-red-50' },
    { label: 'Condition Monitoring', value: data.filter(i => i.taskType === 'Condition Monitoring').length, icon: Zap, color: 'text-indigo-600', bg: 'bg-indigo-50' },
    { label: 'Human factor fixes', value: data.filter(i => i.taskType === 'Training' || i.taskType === 'Procedural Change').length, icon: UserPlus, color: 'text-purple-600', bg: 'bg-purple-50' },
  ];

  const renderSortIcon = (key: keyof RCMItem | 'rpn' | 'status_color' | 'inspectionSheet') => {
    if (sortConfig.key !== key) return <ArrowUpDown size={14} className="text-slate-300" />;
    return sortConfig.direction === 'asc' ? <ArrowUp size={14} className="text-indigo-600" /> : <ArrowDown size={14} className="text-indigo-600" />;
  };

  return (
    <div className="space-y-8 animate-fade-in relative w-full">
      {renderComponentIntelModal()}
      <CMMSBridgeModal data={data} isOpen={showCMMSBridge} onClose={() => setShowCMMSBridge(false)} />

      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        {stats.map((stat, i) => (
           <div key={i} className="bg-white p-6 rounded-2xl shadow-sm border border-slate-200">
            <div className="flex items-center gap-4">
              <div className={`w-12 h-12 rounded-xl ${stat.bg} ${stat.color} flex items-center justify-center shrink-0`}>
                <stat.icon size={24} />
              </div>
              <div>
                <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest leading-none mb-2">{stat.label}</p>
                <h3 className="text-2xl font-bold text-slate-800 leading-none">{stat.value}</h3>
              </div>
            </div>
          </div>
        ))}
      </div>

      <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
        <div className="xl:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200 flex flex-col">
          <div className="flex justify-between items-start mb-6">
            <div><h3 className="text-lg font-bold text-slate-800 flex items-center gap-2"><AlertTriangle size={20} className="text-orange-500" />Criticality Matrix</h3></div>
          </div>
          <div className="flex-1 min-h-[300px] flex items-center justify-center relative">
             <div className="relative w-full max-w-sm aspect-square">
                <div className="grid grid-cols-10 grid-rows-10 gap-0.5 w-full h-full">
                   {Array.from({ length: 100 }).map((_, idx) => {
                      const x = (idx % 10) + 1; const y = 10 - Math.floor(idx / 10); const score = x * y;
                      let bgClass = score >= 50 ? "bg-red-50 border-red-100" : score >= 20 ? "bg-amber-50 border-amber-100" : "bg-emerald-50 border-emerald-100";
                      const isSelected = matrixFilter?.s === x && matrixFilter?.o === y;
                      if (isSelected) bgClass = "bg-indigo-600 border-indigo-700 ring-2 ring-indigo-300 z-10";
                      const count = data.filter(d => (d.severity || 0) === x && (d.occurrence || 0) === y).length;
                      return (<button key={idx} onClick={() => handleMatrixClick(x, y)} className={`border rounded-sm relative transition-all hover:scale-110 flex items-center justify-center ${bgClass}`}>{count > 0 && <span className={`text-[10px] font-black ${isSelected ? 'text-white' : 'text-slate-500'}`}>{count}</span>}</button>);
                   })}
                </div>
             </div>
          </div>
        </div>
        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Risk Profile</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={topRisks} layout="vertical">
                <XAxis type="number" hide />
                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 11}} />
                <Bar dataKey="rpn" fill="#4f46e5" radius={[0, 4, 4, 0]} onClick={(d) => handleBarClick(d.id)} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="p-6 border-b flex flex-wrap justify-between items-center gap-4 bg-slate-50/50">
          <div className="flex items-center gap-3"><FileText size={20} className="text-indigo-600" /><div><h3 className="text-lg font-bold">FMECA Analysis</h3><p className="text-xs text-slate-500">Industry Standard SAE JA1011</p></div></div>
          <div className="flex gap-2">
            <button onClick={handleValidateLogic} disabled={isValidating} className="flex items-center gap-2 px-4 py-2 bg-white border rounded-xl text-xs font-bold hover:bg-slate-50 transition-all">{isValidating ? <Loader2 size={16} className="animate-spin" /> : <ShieldCheck size={16} />} Validate Audit</button>
            <button onClick={() => setShowCMMSBridge(true)} className="flex items-center gap-2 px-4 py-2 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-indigo-600 transition-all"><Layers size={16} /> CMMS Sync</button>
          </div>
        </div>

        <div className="overflow-x-auto custom-scrollbar">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/80 border-b border-slate-200 text-[10px] font-black uppercase tracking-widest text-slate-400">
                <th className="px-6 py-4">Type</th>
                <th className="px-6 py-4">Function / Component</th>
                <th className="px-6 py-4">Failure Mode</th>
                <th className="px-6 py-4 w-12 text-center">S</th>
                <th className="px-6 py-4 w-12 text-center">O</th>
                <th className="px-6 py-4 w-12 text-center">D</th>
                <th className="px-6 py-4 w-16">RPN</th>
                <th className="px-6 py-4">Strategy</th>
                <th className="px-6 py-4 w-16"></th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100 text-sm">
              {processedData.map((item) => {
                const hasIssues = item.validationIssues && item.validationIssues.length > 0;
                const isHumanFactor = item.taskType === 'Training' || item.taskType === 'Procedural Change';

                return (
                  <tr key={item.id} className={`group hover:bg-slate-50/50 ${hasIssues ? 'bg-red-50/10 border-l-4 border-l-red-500' : ''} ${item.isNew ? 'bg-emerald-50/30' : ''}`}>
                    <td className="px-6 py-5 align-top"><span className={`text-[9px] font-black px-2 py-1 rounded border ${item.functionType === 'Primary' ? 'bg-slate-900 text-white border-slate-900' : 'bg-slate-100 text-slate-500 border-slate-200'}`}>{item.functionType}</span></td>
                    <td className="px-6 py-5 align-top">
                      <p className="text-[11px] font-bold text-slate-900 uppercase tracking-tight">{item.function}</p>
                      <div className="flex items-center gap-2 mt-1">
                        <span className="text-[10px] text-slate-500 font-bold uppercase">{item.component}</span>
                        <button onClick={() => handleIntelClick(item)} className="p-1 text-slate-300 hover:text-indigo-600"><Info size={14} /></button>
                      </div>
                    </td>
                    <td className="px-6 py-5 align-top">
                      <p className="text-[11px] font-bold text-slate-700 leading-tight uppercase">{item.failureMode}</p>
                      {hasIssues && <div className="flex items-center gap-1 text-red-500 text-[9px] font-black uppercase mt-1"><ShieldX size={12} /> Logic Risk</div>}
                    </td>
                    <td className="px-6 py-5 align-middle text-center"><span className={getScoreColor(item.severity)}>{item.severity}</span></td>
                    <td className="px-6 py-5 align-middle text-center"><span className={getScoreColor(item.occurrence)}>{item.occurrence}</span></td>
                    <td className="px-6 py-5 align-middle text-center"><span className={getScoreColor(item.detection)}>{item.detection}</span></td>
                    <td className="px-6 py-5 align-middle"><span className="text-xs font-bold text-slate-800">{item.rpn}</span></td>
                    <td className="px-6 py-5 align-top">
                      <p className="text-[11px] font-bold text-indigo-700 leading-tight uppercase">{item.maintenanceTask}</p>
                      <div className="flex items-center gap-2 mt-1">
                        <span className="text-[9px] text-slate-400 font-black uppercase">{item.interval}</span>
                        {isHumanFactor && <span className="text-[8px] bg-purple-50 text-purple-600 px-1.5 py-0.5 rounded border border-purple-100 font-black uppercase">Human Factor Fix</span>}
                      </div>
                    </td>
                    <td className="px-6 py-5 align-middle text-right opacity-0 group-hover:opacity-100 transition-opacity">
                      <div className="flex justify-end gap-1">
                        <button onClick={() => handleEdit(item)} className="p-1.5 text-slate-400 hover:text-indigo-600"><Pencil size={16} /></button>
                        <button onClick={() => handleDelete(item.id)} className="p-1.5 text-slate-400 hover:text-red-600"><Trash2 size={16} /></button>
                      </div>
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};
